const InclusionExclusionEditor: React.FC<{
    title: string;
    items: string[];
    setItems: (items: string[]) => void;
    isEditing: boolean;
    icon: React.ReactNode;
    iconBgColor: string;
}> = ({ title, items, setItems, isEditing, icon, iconBgColor }) => {

    const handleItemChange = (index: number, value: string) => {
        const newItems = [...items];
        newItems[index] = value;
        setItems(newItems);
    };

    const addItem = () => {
        setItems([...items, '']);
    };

    const removeItem = (index: number) => {
        setItems(items.filter((_, i) => i !== index));
    };

    return (
        <div className="bg-white rounded-lg overflow-hidden border border-slate-200 shadow-sm">
            {/* Header */}
            <div className="bg-[#191975] px-4 py-3">
                <div className="flex items-center gap-3">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${iconBgColor}`}>
                        {icon}
                    </div>
                    <h3 className="font-bold text-lg text-white">{title}</h3>
                </div>
            </div>
            {/* Body */}
            <div className="p-4">
                {isEditing ? (
                    <div className="space-y-2">
                        {items.map((item, index) => (
                            <div key={index} className="flex items-center gap-2">
                                <span className="text-slate-400 flex-shrink-0">{iconBgColor.includes('green') ? <CheckIcon className="w-4 h-4 text-green-500" /> : <CrossIcon className="w-4 h-4 text-red-500" />}</span>
                                <input
                                    type="text"
                                    value={item}
                                    onChange={e => handleItemChange(index, e.target.value)}
                                    className="flex-1 text-sm p-2 border border-slate-300 rounded-md bg-slate-50 focus:bg-white focus:border-[#191975] focus:ring-1 focus:ring-[#191975] outline-none"
                                />
                                <button onClick={() => removeItem(index)} className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-md transition-colors"><IconTrash className="w-4 h-4" /></button>
                            </div>
                        ))}
                        <button onClick={addItem} className="w-full px-3 py-2 text-sm font-medium text-white bg-[#191975] rounded-md hover:bg-[#0f0f4d] transition-colors">+ Add Item</button>
                    </div>
                ) : (
                    <ul className="space-y-2">
                        {items.length === 0 ? (
                            <li className="text-sm text-slate-400 italic">No items added</li>
                        ) : (
                            items.map((item, index) => (
                                <li key={index} className="flex items-start gap-2 text-sm text-slate-700">
                                    <span className="mt-0.5 flex-shrink-0">{iconBgColor.includes('green') ? <CheckIcon className="w-4 h-4 text-green-500" /> : <CrossIcon className="w-4 h-4 text-red-500" />}</span>
                                    <span className="flex-1">{item}</span>
                                </li>
                            ))
                        )}
                    </ul>
                )}
            </div>
        </div>
    );
};

