const parseISODurationToMinutes = (durationStr: string | undefined): number => {
    if (!durationStr) return 0;
    const matches = durationStr.match(/PT(?:(\d+)H)?(?:(\d+)M)?/);
    if (!matches) return 0;
    const hours = matches[1] ? parseInt(matches[1]) : 0;
    const minutes = matches[2] ? parseInt(matches[2]) : 0;
    return (hours * 60) + minutes;
};

// Parse duration string to get number of days (handles formats like "7 Days / 6 Nights", "5D/4N", "4 Days", etc.)
const parseDurationToDays = (durationStr: string | undefined): number => {
    if (!durationStr) return 4; // Default to 4 days

    // Try to extract days from various formats
    // Format 1: "7 Days / 6 Nights" or "7 Days/6 Nights"
    const daysMatch1 = durationStr.match(/(\d+)\s*[Dd]ays?/i);
    if (daysMatch1) {
        return parseInt(daysMatch1[1], 10);
    }

    // Format 2: "5D/4N" or "5D 4N"
    const daysMatch2 = durationStr.match(/(\d+)\s*[Dd]/i);
    if (daysMatch2) {
        return parseInt(daysMatch2[1], 10);
    }

    // Format 3: "4N/5D" - extract days
    const daysMatch3 = durationStr.match(/(\d+)\s*[Dd]/i);
    if (daysMatch3) {
        return parseInt(daysMatch3[1], 10);
    }

    // Format 4: "6 Nights" - add 1 day
    const nightsMatch = durationStr.match(/(\d+)\s*[Nn]ights?/i);
    if (nightsMatch) {
        return parseInt(nightsMatch[1], 10) + 1;
    }

    // Format 5: Just a number
    const numberMatch = durationStr.match(/(\d+)/);
    if (numberMatch) {
        return parseInt(numberMatch[1], 10);
    }

    return 4; // Default fallback
};

// Calculate date for a specific day number (Day 1 = travel_date, Day 2 = travel_date + 1 day, etc.)
const getDayDate = (travelDate: string, dayNumber: number): string => {
    if (!travelDate) return '';
    const date = new Date(travelDate);
    date.setDate(date.getDate() + (dayNumber - 1));
    return date.toISOString().split('T')[0];
};

// Calculate distance between two coordinates using Haversine formula (returns distance in km)
const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number): number => {
    if (!lat1 || !lon1 || !lat2 || !lon2) return Infinity;

    const R = 6371; // Earth's radius in km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a =
        Math.sin(dLat / 2) * Math.sin(dLat / 2) +
        Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
        Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
};

// Generate time slots for an attraction based on opening_hours and best_time
const generateTimeSlots = (openingHours: string | undefined, bestTime: BestTime | undefined, durationHours: number | undefined): Array<{ start: string; end: string; label: string }> => {
    const slots: Array<{ start: string; end: string; label: string }> = [];

    if (!openingHours || !durationHours) {
        // Default slots based on best_time
        if (bestTime === 'Morning') {
            slots.push({ start: '08:00', end: '12:00', label: 'Morning' });
            slots.push({ start: '09:00', end: '13:00', label: 'Morning' });
        } else if (bestTime === 'Afternoon') {
            slots.push({ start: '12:00', end: '16:00', label: 'Afternoon' });
            slots.push({ start: '13:00', end: '17:00', label: 'Afternoon' });
        } else if (bestTime === 'Sunset') {
            slots.push({ start: '15:00', end: '19:00', label: 'Sunset' });
            slots.push({ start: '16:00', end: '20:00', label: 'Sunset' });
        } else if (bestTime === 'Night') {
            slots.push({ start: '18:00', end: '22:00', label: 'Night' });
            slots.push({ start: '19:00', end: '23:00', label: 'Night' });
        } else {
            // Default slots
            slots.push({ start: '09:00', end: '13:00', label: 'Morning' });
            slots.push({ start: '14:00', end: '18:00', label: 'Afternoon' });
        }
        return slots;
    }

    // Parse opening hours (format: "10:00-19:00" or "09:00-21:00")
    const hoursMatch = openingHours.match(/(\d{2}):(\d{2})-(\d{2}):(\d{2})/);
    if (hoursMatch) {
        const openHour = parseInt(hoursMatch[1], 10);
        const openMin = parseInt(hoursMatch[2], 10);
        const closeHour = parseInt(hoursMatch[3], 10);
        const closeMin = parseInt(hoursMatch[4], 10);

        const openTime = openHour * 60 + openMin; // minutes from midnight
        const closeTime = closeHour * 60 + closeMin;
        const durationMinutes = durationHours * 60;

        // Generate 2-3 slots based on best_time
        if (bestTime === 'Morning') {
            // Morning slots: start early, end before afternoon
            const slot1Start = openTime;
            const slot1End = Math.min(slot1Start + durationMinutes, openTime + 4 * 60); // Max 4 hours
            if (slot1End <= closeTime) {
                slots.push({
                    start: `${Math.floor(slot1Start / 60).toString().padStart(2, '0')}:${(slot1Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot1End / 60).toString().padStart(2, '0')}:${(slot1End % 60).toString().padStart(2, '0')}`,
                    label: 'Morning'
                });
            }

            const slot2Start = openTime + 60; // 1 hour later
            const slot2End = Math.min(slot2Start + durationMinutes, openTime + 5 * 60);
            if (slot2End <= closeTime && slot2Start < 12 * 60) {
                slots.push({
                    start: `${Math.floor(slot2Start / 60).toString().padStart(2, '0')}:${(slot2Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot2End / 60).toString().padStart(2, '0')}:${(slot2End % 60).toString().padStart(2, '0')}`,
                    label: 'Morning'
                });
            }
        } else if (bestTime === 'Afternoon') {
            // Afternoon slots: start around noon
            const slot1Start = Math.max(12 * 60, openTime); // Start at 12:00 or opening time
            const slot1End = Math.min(slot1Start + durationMinutes, closeTime);
            if (slot1End <= closeTime) {
                slots.push({
                    start: `${Math.floor(slot1Start / 60).toString().padStart(2, '0')}:${(slot1Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot1End / 60).toString().padStart(2, '0')}:${(slot1End % 60).toString().padStart(2, '0')}`,
                    label: 'Afternoon'
                });
            }

            const slot2Start = slot1Start + 60;
            const slot2End = Math.min(slot2Start + durationMinutes, closeTime);
            if (slot2End <= closeTime && slot2Start < 16 * 60) {
                slots.push({
                    start: `${Math.floor(slot2Start / 60).toString().padStart(2, '0')}:${(slot2Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot2End / 60).toString().padStart(2, '0')}:${(slot2End % 60).toString().padStart(2, '0')}`,
                    label: 'Afternoon'
                });
            }
        } else if (bestTime === 'Sunset') {
            // Sunset slots: start around 3-4 PM
            const slot1Start = Math.max(15 * 60, openTime);
            const slot1End = Math.min(slot1Start + durationMinutes, closeTime);
            if (slot1End <= closeTime) {
                slots.push({
                    start: `${Math.floor(slot1Start / 60).toString().padStart(2, '0')}:${(slot1Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot1End / 60).toString().padStart(2, '0')}:${(slot1End % 60).toString().padStart(2, '0')}`,
                    label: 'Sunset'
                });
            }

            const slot2Start = slot1Start + 60;
            const slot2End = Math.min(slot2Start + durationMinutes, closeTime);
            if (slot2End <= closeTime && slot2Start < 19 * 60) {
                slots.push({
                    start: `${Math.floor(slot2Start / 60).toString().padStart(2, '0')}:${(slot2Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot2End / 60).toString().padStart(2, '0')}:${(slot2End % 60).toString().padStart(2, '0')}`,
                    label: 'Sunset'
                });
            }
        } else if (bestTime === 'Night') {
            // Night slots: start after 6 PM
            const slot1Start = Math.max(18 * 60, openTime);
            const slot1End = Math.min(slot1Start + durationMinutes, closeTime);
            if (slot1End <= closeTime) {
                slots.push({
                    start: `${Math.floor(slot1Start / 60).toString().padStart(2, '0')}:${(slot1Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot1End / 60).toString().padStart(2, '0')}:${(slot1End % 60).toString().padStart(2, '0')}`,
                    label: 'Night'
                });
            }

            const slot2Start = slot1Start + 60;
            const slot2End = Math.min(slot2Start + durationMinutes, closeTime);
            if (slot2End <= closeTime) {
                slots.push({
                    start: `${Math.floor(slot2Start / 60).toString().padStart(2, '0')}:${(slot2Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot2End / 60).toString().padStart(2, '0')}:${(slot2End % 60).toString().padStart(2, '0')}`,
                    label: 'Night'
                });
            }
        } else {
            // Default: generate 2-3 slots throughout the day
            const slot1Start = openTime;
            const slot1End = Math.min(slot1Start + durationMinutes, closeTime);
            if (slot1End <= closeTime) {
                slots.push({
                    start: `${Math.floor(slot1Start / 60).toString().padStart(2, '0')}:${(slot1Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot1End / 60).toString().padStart(2, '0')}:${(slot1End % 60).toString().padStart(2, '0')}`,
                    label: 'Morning'
                });
            }

            const slot2Start = Math.floor((openTime + closeTime) / 2); // Middle of the day
            const slot2End = Math.min(slot2Start + durationMinutes, closeTime);
            if (slot2End <= closeTime && slot2Start > slot1End) {
                slots.push({
                    start: `${Math.floor(slot2Start / 60).toString().padStart(2, '0')}:${(slot2Start % 60).toString().padStart(2, '0')}`,
                    end: `${Math.floor(slot2End / 60).toString().padStart(2, '0')}:${(slot2End % 60).toString().padStart(2, '0')}`,
                    label: 'Afternoon'
                });
            }
        }
    }

    return slots.slice(0, 3); // Return max 3 slots
};

const getItineraryStatusClass = (status?: ItineraryStatus) => {
    switch (status) {
        case ItineraryStatus.Confirmed:
            return 'bg-green-600 text-white';
        case ItineraryStatus.Sent:
            return 'bg-green-400 text-white';
        case ItineraryStatus.Prepared:
            return 'bg-yellow-400 text-white';
        case ItineraryStatus.Archived:
            return 'bg-slate-100 text-slate-800';
        default:
            return 'bg-yellow-400 text-white';
    }
};

const ItineraryStatusBadge: React.FC<{ status?: ItineraryStatus }> = ({ status }) => (
    <span className={`px-2 py-0.5 text-xs font-medium rounded-full ${getItineraryStatusClass(status)}`}>
        {status || 'N/A'}
    </span>
);

const ItineraryGrid: React.FC<{
    itineraries: ItineraryMetadata[];
    customerMap: Map<number, Customer>;
    leads: Lead[];
    staff: Staff[];
    onSelect: (meta: ItineraryMetadata) => void;
    activeTab: 'Active' | 'Archived';
    onArchive: (meta: ItineraryMetadata) => void;
    onRestore: (meta: ItineraryMetadata) => void;
    onClone?: (meta: ItineraryMetadata) => void;
    onDelete?: (meta: ItineraryMetadata) => void;
    isSuperAdmin?: boolean;
    onNavigateLead: (e: React.MouseEvent, leadId: number) => void;
}> = ({ itineraries, customerMap, leads, staff, onSelect, activeTab, onArchive, onRestore, onClone, onDelete, isSuperAdmin, onNavigateLead }) => {
    // Helper to get currency symbol
    const getCurrencySymbol = (currency: Currency): string => {
        const symbols: Record<Currency, string> = {
            'INR': '₹', 'USD': '$', 'EUR': '€', 'GBP': '£', 'AUD': 'A$', 'CAD': 'C$',
            'SGD': 'S$', 'JPY': '¥', 'CHF': 'CHF', 'CNY': '¥', 'NZD': 'NZ$'
        };
        return symbols[currency] || currency;
    };

    // Helper to format currency
    const formatCurrency = (amount: number, currency: Currency): string => {
        if (currency === 'INR') {
            return `₹ ${amount.toLocaleString('en-IN', { maximumFractionDigits: 0 })}`;
        }
        const symbol = getCurrencySymbol(currency);
        const locale = currency === 'USD' || currency === 'CAD' || currency === 'AUD' || currency === 'NZD' ? 'en-US' :
                      currency === 'GBP' ? 'en-GB' :
                      currency === 'EUR' ? 'de-DE' :
                      currency === 'JPY' || currency === 'CNY' ? 'ja-JP' : 'en-IN';
        return `${symbol} ${amount.toLocaleString(locale, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
    };

    // Get grand total from stored version data (no recalculation)
    // Returns grand total only if amount > 0, so the card shows for all itineraries with valid totals
    const getGrandTotal = (meta: ItineraryMetadata): { amount: number; currency: Currency } | null => {
        // Get latest version
        if (!meta.itinerary_versions || meta.itinerary_versions.length === 0) return null;
        
        const latestVersion = meta.itinerary_versions
            .sort((a, b) => b.version_number - a.version_number)[0];
        
        // Get grand total from the version's grand_total column (stored in INR)
        const grandTotalInr = (latestVersion as any).grand_total;
        
        // Return null if grand_total doesn't exist or is 0 or less
        // This ensures the card only shows for itineraries with total amount > 0
        if (grandTotalInr === undefined || grandTotalInr === null || grandTotalInr === 0 || grandTotalInr <= 0) {
            return null;
        }

        const displayCurrency = (meta as any).display_currency || 'INR';
        
        // Grand total is stored in INR, return as-is (no conversion needed for display)
        // The display currency is just for formatting, the amount is always in INR
        return { amount: Number(grandTotalInr), currency: displayCurrency };
    };

    return (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-2 sm:gap-3 lg:gap-3 pb-20 sm:pb-0">
            {itineraries.map(meta => {
                const customer = customerMap.get(meta.customer_id);
                const lead = leads.find(l => l.id === meta.lead_id);
                const staffCreator = staff.find(s => s.id === meta.created_by_staff_id);
                const latestVersion = meta.itinerary_versions?.length > 0
                    ? Math.max(...meta.itinerary_versions.map(v => v.version_number))
                    : 0;
                
                const grandTotal = getGrandTotal(meta);

                return (
                    <div key={meta.id} onClick={() => onSelect(meta)} className="bg-white rounded-xl border border-slate-200 shadow-sm hover:shadow-md cursor-pointer transition-all overflow-hidden flex flex-col relative group">
                        {/* Image Section - Full width on mobile */}
                        <div className="w-full h-32 sm:h-36 lg:h-32 bg-gradient-to-br from-slate-100 to-slate-200 relative overflow-hidden">
                            <img
                                src={meta.cover_image_url || 'https://placehold.co/600x400?text=No+Image'}
                                alt={meta.creative_title}
                                className="w-full h-full object-cover"
                            />
                            {/* Status Badge - Top Right */}
                            <div className="absolute top-1.5 right-1.5">
                                <ItineraryStatusBadge status={meta.status} />
                            </div>
                            {/* Grand Total - Bottom Right */}
                            {grandTotal && grandTotal.amount > 0 && (
                                <div className="absolute bottom-1.5 right-1.5 bg-white/95 backdrop-blur-sm rounded-md shadow-lg px-2 py-1 sm:px-2.5 sm:py-1.5 border border-slate-200">
                                    <div className="text-[8px] sm:text-[10px] text-slate-500 mb-0.5 uppercase tracking-wide font-medium">Total</div>
                                    <div className="text-xs sm:text-sm font-bold text-[#191974] tabular-nums">
                                        {formatCurrency(grandTotal.amount, grandTotal.currency)}
                                    </div>
                                </div>
                            )}
                        </div>
                        
                        {/* Content Section - Compact for 4-col */}
                        <div className="p-3 sm:p-3.5 lg:p-3 flex flex-col flex-1">
                            {/* Title and Duration */}
                            <div className="mb-2">
                                <h3 className="font-bold text-xs sm:text-sm text-slate-900 line-clamp-2 leading-snug mb-1" title={meta.creative_title}>
                                    {meta.creative_title}
                                </h3>
                                <div className="flex items-center gap-1.5 text-[10px] sm:text-xs text-slate-500">
                                    <span>{meta.duration}</span>
                                    {latestVersion > 0 && (
                                        <>
                                            <span className="text-slate-300">•</span>
                                            <span className="font-medium">v{latestVersion}</span>
                                        </>
                                    )}
                                </div>
                            </div>

                            {/* Key Info - Compact */}
                            <div className="space-y-1.5 mb-3 flex-1">
                                {customer && (
                                    <div className="flex items-center gap-2 text-[10px] sm:text-xs text-slate-700">
                                        <div className="flex items-center gap-1 min-w-0 flex-1">
                                            <span className="text-slate-500 font-medium flex-shrink-0">Customer:</span>
                                            <span className="truncate font-medium">{customer.first_name} {customer.last_name}</span>
                                        </div>
                                    </div>
                                )}
                                {lead && (
                                    <div className="flex items-center gap-2 text-[10px] sm:text-xs">
                                        <div className="flex items-center gap-1 min-w-0 flex-1">
                                            <span className="text-slate-500 font-medium flex-shrink-0">Lead:</span>
                                            <span 
                                                onClick={(e) => onNavigateLead(e, lead.id)} 
                                                className="text-blue-600 hover:underline cursor-pointer truncate font-medium"
                                            >
                                                {generateBookingId(lead)}
                                            </span>
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* Footer - Compact */}
                            <div className="border-t border-slate-100 pt-2 flex justify-between items-center">
                                <div className="flex items-center gap-1.5 text-[10px] sm:text-xs text-slate-500">
                                    {staffCreator && (
                                        <img 
                                            src={staffCreator.avatar_url} 
                                            className="w-4 h-4 rounded-full border border-slate-200" 
                                            title={staffCreator.name}
                                            alt={staffCreator.name}
                                        />
                                    )}
                                    <span>{new Date(meta.modified_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span>
                                </div>
                                <div className="flex gap-0.5">
                                    {activeTab === 'Active' && onClone && (
                                        <button onClick={(e) => { e.stopPropagation(); onClone(meta); }} className="p-1 sm:p-1.5 text-slate-400 hover:text-blue-600 rounded-md hover:bg-blue-50 transition-colors" title="Clone">
                                            <svg className="w-3.5 h-3.5 sm:w-4 sm:h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                                        </button>
                                    )}
                                    {activeTab === 'Active' ? (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onArchive(meta); }} 
                                            className="p-1 sm:p-1.5 text-slate-400 hover:text-red-600 rounded-md hover:bg-red-50 transition-colors" 
                                            title="Archive"
                                        >
                                            <IconTrash className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                                        </button>
                                    ) : (
                                        <>
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); onRestore(meta); }} 
                                                className="p-1 sm:p-1.5 text-slate-400 hover:text-green-600 rounded-md hover:bg-green-50 transition-colors" 
                                                title="Restore"
                                            >
                                                <IconRefresh className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                                            </button>
                                            {isSuperAdmin && onDelete && (
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); onDelete(meta); }} 
                                                    className="p-1 sm:p-1.5 text-red-500 hover:text-red-700 rounded-md hover:bg-red-50 transition-colors" 
                                                    title="Permanently Delete"
                                                >
                                                    <IconTrash className="w-3.5 h-3.5 sm:w-4 sm:h-4" />
                                                </button>
                                            )}
                                        </>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                );
            })}
        </div>
    );
};

// Forward declare interface for ItineraryDetailView
interface ItineraryDetailViewProps {
    itineraryMetadata: ItineraryMetadata | null;
    lead: Lead | null;
    customer: Customer | null;
    destination?: Destination | null;
    initialTemplateMeta?: { duration: string; creative_title: string } | null;
    onClose: () => void;
    onSave: (itinerary: Itinerary, metaUpdates: Partial<ItineraryMetadata>, status: ItineraryStatus, imageFiles: { cover: File | null, gallery: (File | null)[] }) => Promise<ItineraryMetadata | null>;
    currentUser: LoggedInUser;
    onStatusUpdate: (itineraryId: number, status: ItineraryStatus) => Promise<void>;
    refreshData: () => Promise<void>;
    invoices: Invoice[];
    isCreating?: boolean;
}

export const Itineraries: React.FC<{ currentUser: LoggedInUser }> = ({ currentUser }) => {
    const { itineraries, leads, customers, invoices, refreshData, destinations } = useData();
    const { pathname, navigate } = useRouter();
    const [view, setView] = useState<'list' | 'detail'>('list');
    const [selectedItineraryMetadata, setSelectedItineraryMetadata] = useState<ItineraryMetadata | null>(null);
    const [isCreating, setIsCreating] = useState(false);
    const [contextualData, setContextualData] = useState<{ lead: Lead | null, customer: Customer | null, destination: Destination | null }>({ lead: null, customer: null, destination: null });
    const [templateInitialMeta, setTemplateInitialMeta] = useState<{ duration: string; creative_title: string } | null>(null);
    const { addToast } = useToast();

    // Handle URL-based routing: /itineraries/{destination}/{duration}/{mtsid}
    useEffect(() => {
        const urlParams = parseItineraryUrl(pathname);
        
        // Check for new itinerary from sessionStorage (backward compatibility)
        const newItineraryForLead = sessionStorage.getItem('newItineraryForLead');
        const itineraryIdToView = sessionStorage.getItem('viewItineraryId');
        let didStartNewItineraryFromLead = false;

        if (newItineraryForLead) {
            sessionStorage.removeItem('newItineraryForLead');
            try {
                const lead: Lead = JSON.parse(newItineraryForLead);
                const customer = lead.customer_id ? customers.find(c => c.id === lead.customer_id) : null;
                if (lead) {
                    const destination = destinations.find(d => d.name === lead.destination) || null;
                    setContextualData({ lead, customer: customer || null, destination });
                    setIsCreating(true);
                    setView('detail');
                    didStartNewItineraryFromLead = true;
                }
            } catch (e) {
                addToast('Failed to start new itinerary from lead.', 'error');
            }
        } else if (urlParams && urlParams.isDestinationUrl && urlParams.itineraryId) {
            // Destination/template itinerary URL: /itineraries/{destination}/{duration}/destination/{itineraryId}
            const itineraryIdNum = parseInt(urlParams.itineraryId, 10);
            if (!isNaN(itineraryIdNum)) {
                let meta = itineraries.find(i => i.id === itineraryIdNum);
                if (meta) {
                    setContextualData({ lead: null, customer: meta.customer_id ? customers.find(c => c.id === meta.customer_id) || null : null, destination: destinations.find(d => d.name === meta.destination) || null });
                    (async () => {
                        try {
                            const { data: freshMeta } = await supabase.from('itineraries').select('*').eq('id', meta!.id).single();
                            setSelectedItineraryMetadata(freshMeta || meta);
                        } catch {
                            setSelectedItineraryMetadata(meta);
                        }
                    })();
                    setView('detail');
                } else {
                    (async () => {
                        try {
                            const { data: fetchedMeta } = await supabase.from('itineraries').select('*').eq('id', itineraryIdNum).single();
                            if (fetchedMeta) {
                                setContextualData({ lead: null, customer: fetchedMeta.customer_id ? customers.find(c => c.id === fetchedMeta.customer_id) || null : null, destination: destinations.find(d => d.name === fetchedMeta.destination) || null });
                                setSelectedItineraryMetadata(fetchedMeta);
                                setView('detail');
                            }
                        } catch { /* not found */ }
                    })();
                }
            }
        } else if (urlParams && urlParams.mtsId && leads.length > 0) {
            const itineraryIdNum = urlParams.itineraryId ? parseInt(urlParams.itineraryId, 10) : null;
            const matchingLead = leads.find(l => generateBookingId(l) === urlParams.mtsId);

            // Prefer resolution by itinerary ID (unique per itinerary; works for multiple itineraries per lead and archived)
            if (itineraryIdNum && !isNaN(itineraryIdNum)) {
                let meta = itineraries.find(i => i.id === itineraryIdNum);
                if (meta) {
                    const lead = meta.lead_id ? leads.find(l => l.id === meta.lead_id) || matchingLead : matchingLead;
                    const customer = meta.customer_id ? customers.find(c => c.id === meta.customer_id) : null;
                    const destination = destinations.find(d => d.name === meta.destination) || null;
                    setContextualData({ lead: lead || null, customer: customer || null, destination });
                    if (!meta.lead_id) navigate(generateItineraryUrl(meta, null));
                    (async () => {
                        try {
                            const { data: freshMeta } = await supabase.from('itineraries').select('*').eq('id', meta!.id).single();
                            setSelectedItineraryMetadata(freshMeta || meta);
                        } catch {
                            setSelectedItineraryMetadata(meta);
                        }
                    })();
                    setView('detail');
                } else {
                    // Itinerary not in current list (e.g. archived) – fetch by id
                    (async () => {
                        try {
                            const { data: fetchedMeta } = await supabase.from('itineraries').select('*').eq('id', itineraryIdNum).single();
                            if (fetchedMeta) {
                                const lead = fetchedMeta.lead_id ? leads.find(l => l.id === fetchedMeta.lead_id) || matchingLead : matchingLead;
                                const customer = fetchedMeta.customer_id ? customers.find(c => c.id === fetchedMeta.customer_id) : null;
                                const destination = destinations.find(d => d.name === fetchedMeta.destination) || null;
                                setContextualData({ lead: lead || null, customer: customer || null, destination });
                                if (!fetchedMeta.lead_id) navigate(generateItineraryUrl(fetchedMeta, null));
                                setSelectedItineraryMetadata(fetchedMeta);
                                setView('detail');
                            }
                        } catch {
                            // Not found or error – fall through to legacy mtsId-only resolution
                        }
                    })();
                }
            } else if (matchingLead && itineraries.length > 0) {
                // Legacy URL (no itineraryId): use first itinerary for this lead
                const meta = itineraries.find(i => i.lead_id === matchingLead.id);
                if (meta) {
                    const lead = matchingLead;
                    const customer = meta.customer_id ? customers.find(c => c.id === meta.customer_id) : null;
                    const destination = destinations.find(d => d.name === meta.destination) || null;
                    setContextualData({ lead: lead || null, customer: customer || null, destination });
                    (async () => {
                        try {
                            const { data: freshMeta } = await supabase.from('itineraries').select('*').eq('id', meta.id).single();
                            setSelectedItineraryMetadata(freshMeta || meta);
                        } catch {
                            setSelectedItineraryMetadata(meta);
                        }
                    })();
                    setView('detail');
                }
            }
        } else if (itineraryIdToView && itineraries.length > 0) {
            // Backward compatibility: handle old sessionStorage approach
            sessionStorage.removeItem('viewItineraryId');
            const meta = itineraries.find(i => i.id === parseInt(itineraryIdToView, 10));
            if (meta) {
                const lead = meta.lead_id ? leads.find(l => l.id === meta.lead_id) : null;
                const customer = meta.customer_id ? customers.find(c => c.id === meta.customer_id) : null;
                const destination = destinations.find(d => d.name === meta.destination) || null;
                setContextualData({ lead: lead || null, customer: customer || null, destination });
                
                // Navigate to URL (lead-based or destination-based)
                navigate(generateItineraryUrl(meta, lead));
                
                // Fetch fresh metadata
                (async () => {
                    try {
                        const { data: freshMeta } = await supabase
                            .from('itineraries')
                            .select('*')
                            .eq('id', meta.id)
                            .single();
                        if (freshMeta) {
                            setSelectedItineraryMetadata(freshMeta);
                        } else {
                            setSelectedItineraryMetadata(meta);
                        }
                    } catch {
                        setSelectedItineraryMetadata(meta);
                    }
                })();
                
                setView('detail');
            }
        } else if (pathname === '/itineraries' && !didStartNewItineraryFromLead) {
            if (!contextualData.lead || !isCreating) {
                setView('list');
                setSelectedItineraryMetadata(null);
                setIsCreating(false);
                setContextualData({ lead: null, customer: null, destination: null });
            }
        }
    }, [pathname, customers, itineraries, leads, addToast, navigate, contextualData.lead, isCreating]);

    const handleSelectItinerary = async (meta: ItineraryMetadata) => {
        const lead = meta.lead_id ? leads.find(l => l.id === meta.lead_id) : null;
        const customer = meta.customer_id ? customers.find(c => c.id === meta.customer_id) : null;
        // Allow viewing existing itineraries even without lead/customer (for backward compatibility)
        setContextualData({ lead: lead || null, customer: customer || null, destination: destinations.find(d => d.name === meta.destination) || null });
        
        // Navigate to URL (lead-based or destination-based)
        navigate(generateItineraryUrl(meta, lead));
        
        // Refresh itinerary metadata to ensure display_currency is up to date
        if (meta.id) {
            const { data: refreshedMeta } = await supabase
                .from('itineraries')
                .select('*')
                .eq('id', meta.id)
                .single();
            if (refreshedMeta) {
                setSelectedItineraryMetadata(refreshedMeta);
            } else {
                setSelectedItineraryMetadata(meta);
            }
        } else {
            setSelectedItineraryMetadata(meta);
        }
        
        // Don't fetch versions here - let ItineraryDetailView fetch only the latest version on-demand
        setView('detail');
        setIsCreating(false);
    };

    const handleCloseDetailView = () => {
        navigate('/itineraries');
        setView('list');
        setSelectedItineraryMetadata(null);
        setIsCreating(false);
        setContextualData({ lead: null, customer: null, destination: null });
        setTemplateInitialMeta(null);
    };

    const handleSaveItinerary = async (itineraryToSave: Itinerary, metaUpdates: Partial<ItineraryMetadata>, status: ItineraryStatus, imageFiles: { cover: File | null, gallery: (File | null)[] }): Promise<ItineraryMetadata | null> => {
        // Destination-primary: allow creating without lead (template). When editing, allow missing lead/customer for templates.
        const isTemplate = !contextualData.lead;
        if (isCreating && !contextualData.lead && !metaUpdates.destination) {
            addToast('Please set a destination for the itinerary.', 'error');
            return null;
        }
        if (!isCreating && !isTemplate && (!contextualData.lead || !contextualData.customer)) {
            addToast('Missing lead or customer context.', 'error');
            return null;
        }

        const uploadImage = async (file: File, itineraryId: number, type: string): Promise<string> => {
            const filePath = `public/itinerary-images/${itineraryId}/${type}-${Date.now()}-${file.name}`;
            const { error } = await supabase.storage.from('avatars').upload(filePath, file);
            if (error) throw error;
            const { data } = supabase.storage.from('avatars').getPublicUrl(filePath);
            return data.publicUrl;
        };

        let savedMetaId: number;

        // Check if payment link exists for this lead (only if lead exists)
        const hasPaymentLink = contextualData.lead ? (invoices?.some(inv =>
            inv.lead_id === contextualData.lead!.id &&
            inv.razorpay_payment_link_url &&
            inv.razorpay_payment_link_url.trim() !== ''
        ) || false) : false;

        try {
            if (isCreating) {
                // === CREATE NEW ITINERARY AND FIRST VERSION ===
                // Use destination name from contextualData or metaUpdates
                const destinationName = contextualData.destination?.name || metaUpdates.destination || '';

                // Convert empty date strings to null (PostgreSQL doesn't accept empty strings for date fields)
                const travelDate = metaUpdates.travel_date && metaUpdates.travel_date.trim() !== ''
                    ? metaUpdates.travel_date
                    : null;

                const { data: newMetaData, error: metaError } = await supabase.from('itineraries').insert({
                    lead_id: contextualData.lead?.id ?? null,
                    customer_id: metaUpdates.customer_id ?? contextualData.customer?.id ?? null,
                    creative_title: metaUpdates.creative_title,
                    duration: metaUpdates.duration,
                    destination: destinationName,
                    travel_date: travelDate,
                    starting_point: metaUpdates.starting_point,
                    adults: metaUpdates.adults,
                    children: metaUpdates.children,
                    infants: metaUpdates.infants,
                    created_by_staff_id: currentUser.id,
                    branch_id: contextualData.lead?.branch_ids?.[0] || currentUser.branch_id || null,
                    is_final: false,
                    modified_at: new Date().toISOString(),
                    status: status,
                    show_payment_button: hasPaymentLink,
                    emergency_contacts: (metaUpdates as any).emergency_contacts || [],
                }).select().single();
                if (metaError) throw metaError;
                savedMetaId = newMetaData.id;

                let finalCoverUrl: string | null = null;
                if (imageFiles.cover) {
                    finalCoverUrl = await uploadImage(imageFiles.cover, savedMetaId, 'cover');
                }
                const galleryUploadPromises = imageFiles.gallery.map((file, i) => file ? uploadImage(file, savedMetaId, `gallery-${i}`) : Promise.resolve(null));
                const finalGalleryUrls = (await Promise.all(galleryUploadPromises)).filter((url): url is string => url !== null);

                await supabase.from('itineraries').update({ cover_image_url: finalCoverUrl, gallery_image_urls: finalGalleryUrls }).eq('id', savedMetaId);

                // Link itinerary to lead if lead exists
                if (contextualData.lead) {
                    await supabase.from('leads').update({ itinerary_ids: [...(contextualData.lead.itinerary_ids || []), savedMetaId] }).eq('id', contextualData.lead.id);
                }

                // Calculate grand total for storage (reuse the same function from update path)
                // This will be defined below in the update path, but we'll call it here too
                const grandTotal = await (async () => {
                    const costingOption = itineraryToSave.costing_options?.[0];
                    if (!costingOption) return 0;

                    const adults = contextualData.lead?.requirements?.adults || metaUpdates.adults || 0;
                    const children = contextualData.lead?.requirements?.children || metaUpdates.children || 0;
                    const infants = contextualData.lead?.requirements?.babies || metaUpdates.infants || 0;

                    if (costingOption.isManualCosting) {
                        // Manual costing
                        const subtotal = costingOption.manualPackageCost || 0;
                        let gst = 0;
                        let tcs = 0;
                        const flightFee = (costingOption.manualFlightPerAdult || 0) * adults +
                                         (costingOption.manualFlightPerChild || 0) * children +
                                         (costingOption.manualFlightPerInfant || 0) * infants;

                        if (costingOption.isGstApplied) {
                            const gstPercent = costingOption.gstPercentage || 5;
                            gst = subtotal * (gstPercent / 100);
                        }
                        if (costingOption.isTcsApplied) {
                            const tcsPercent = costingOption.tcsPercentage || 5;
                            tcs = (subtotal + gst) * (tcsPercent / 100);
                        }

                        return subtotal + gst + tcs + flightFee;
                    } else {
                        // Itemized costing - calculate full grand total
                        // Fetch FX rates
                        let fxRates: Record<Currency, number> | null = null;
                        try {
                            const { data: ratesData } = await supabase
                                .from('fx_rates')
                                .select('currency, rate_to_inr')
                                .eq('is_active', true);
                            
                            if (ratesData) {
                                fxRates = {} as Record<Currency, number>;
                                ratesData.forEach(r => {
                                    fxRates![r.currency as Currency] = r.rate_to_inr || 1;
                                });
                                fxRates['INR'] = 1;
                            }
                        } catch (error) {
                            console.error('Failed to fetch FX rates for grand total calculation:', error);
                        }

                        if (!fxRates) return 0;

                        // Calculate base package and flights separately
                        // Flights should NOT have markup/discount applied - they're separate
                        let basePackageSubtotal = 0;
                        let flightFee = 0;
                        const categoryEnabled = costingOption.categoryEnabled || {};

                        // Process all costing categories
                        Object.entries(costingOption.costing || {}).forEach(([category, items]) => {
                            if (!Array.isArray(items) || items.length === 0) return;
                            if (!categoryEnabled[category as keyof typeof categoryEnabled]) return;
                            
                            const isFlight = category.startsWith('flights');
                            
                            items.forEach(item => {
                                if (!item.included || item.unitPrice === 0) return;
                                
                                const nights = (isFlight || category === 'sightseeing' || category === 'transfers' || category === 'visa' || category === 'insurance') 
                                    ? 1 
                                    : ((item as HotelCostingItem).nights || 1);
                                
                                const fxRate = fxRates![item.currency] || (item.currency === 'INR' ? 1 : 1);
                                
                                let effectiveQuantity = item.quantity || 1;
                                if (isFlight || category === 'transfers' || category === 'visa' || category === 'insurance') {
                                    const pricingType = item.pricingType || 'Per Adult';
                                    if (pricingType === 'Per Adult') effectiveQuantity = adults;
                                    else if (pricingType === 'Per Child') effectiveQuantity = children;
                                    else if (pricingType === 'Per Infant') effectiveQuantity = infants;
                                }
                                
                                if (isFlight) {
                                    // Flights: unitPrice × effectiveQuantity × fxRate (no markup, no discount)
                                    const flightCost = item.unitPrice * effectiveQuantity * fxRate;
                                    flightFee += flightCost;
                                } else {
                                    // Base package items: ((unitPrice × qty × FX_rate × nights) + 2) × 1.15
                                    const baseAmount = item.unitPrice * effectiveQuantity * fxRate * nights;
                                    const itemCost = (baseAmount + 2) * 1.15;
                                    basePackageSubtotal += itemCost;
                                }
                            });
                        });

                        // Apply markup ONLY to base package (not flights)
                        const markup = costingOption.markup || 0;
                        if (markup > 0) {
                            basePackageSubtotal = basePackageSubtotal * (1 + markup / 100);
                        }

                        // Apply discount ONLY to base package (not flights)
                        const discount = costingOption.discount || 0;
                        let discountAmount = 0;
                        if (discount > 0) {
                            discountAmount = basePackageSubtotal * (discount / 100);
                            basePackageSubtotal -= discountAmount;
                        }

                        // Calculate GST/TCS on base package (excluding flights)
                        let gst = 0;
                        let tcs = 0;

                        if (costingOption.isGstApplied) {
                            const gstPercent = costingOption.gstPercentage || 5;
                            gst = basePackageSubtotal * (gstPercent / 100);
                        }
                        if (costingOption.isTcsApplied) {
                            const tcsPercent = costingOption.tcsPercentage || 5;
                            tcs = (basePackageSubtotal + gst) * (tcsPercent / 100);
                        }

                        // Grand Total = Base Package + GST + TCS + Flight Fee
                        return basePackageSubtotal + gst + tcs + flightFee;
                    }
                })();

                const { id, itinerary_id, version_number, ...restOfItinerary } = itineraryToSave as Itinerary;
                const newVersionData = {
                    ...restOfItinerary,
                    itinerary_id: savedMetaId, version_number: 1, modified_at: new Date().toISOString(),
                    modified_by_staff_id: currentUser.id, cover_image_url: finalCoverUrl, gallery_image_urls: finalGalleryUrls,
                    grand_total: grandTotal > 0 ? grandTotal : null,
                };
                const { error: versionError } = await supabase.from('itinerary_versions').insert(newVersionData);
                if (versionError) throw versionError;

                addToast('Itinerary created successfully!', 'success');
            } else {
                // === UPDATE EXISTING ITINERARY ===
                const metaRecord = selectedItineraryMetadata!;
                savedMetaId = metaRecord.id;
                const versions = [...(metaRecord.itinerary_versions || [])].sort((a, b) => b.version_number - a.version_number);

                // Always treat a Save as content change for existing itineraries.
                // This guarantees that all edits to day-wise plan, flights, hotels, transfers,
                // costing, visa, insurance, inclusions, exclusions, etc. are persisted as a new version.

                let finalCoverUrl = metaRecord.cover_image_url;
                if (imageFiles.cover) finalCoverUrl = await uploadImage(imageFiles.cover, savedMetaId, 'cover');

                let finalGalleryUrls = [...(metaRecord.gallery_image_urls || [])];
                const galleryUploadPromises = imageFiles.gallery.map(async (file, i) => { if (file) finalGalleryUrls[i] = await uploadImage(file, savedMetaId, `gallery-${i}`); });
                await Promise.all(galleryUploadPromises);
                finalGalleryUrls = finalGalleryUrls.filter(Boolean) as string[];

                // Convert empty date strings to null (PostgreSQL doesn't accept empty strings for date fields)
                const travelDate = metaUpdates.travel_date && metaUpdates.travel_date.trim() !== ''
                    ? metaUpdates.travel_date
                    : null;

                const updateData: any = {
                    creative_title: metaUpdates.creative_title,
                    duration: metaUpdates.duration,
                    destination: metaUpdates.destination,
                    travel_date: travelDate,
                    starting_point: metaUpdates.starting_point,
                    adults: metaUpdates.adults,
                    children: metaUpdates.children,
                    infants: metaUpdates.infants,
                    modified_at: new Date().toISOString(),
                    cover_image_url: finalCoverUrl,
                    gallery_image_urls: finalGalleryUrls,
                    status: status,
                    show_payment_button: metaRecord.show_payment_button !== undefined ? metaRecord.show_payment_button : hasPaymentLink,
                    display_currency: (metaUpdates as any).display_currency || 'INR',
                    emergency_contacts: (metaUpdates as any).emergency_contacts || []
                };

                // Include customer_id if provided in metaUpdates
                if (metaUpdates.customer_id !== undefined) {
                    updateData.customer_id = metaUpdates.customer_id;
                }

                const { error: metaUpdateError } = await supabase.from('itineraries').update(updateData).eq('id', savedMetaId).select('id').single();
                if (metaUpdateError) {
                    throw new Error(metaUpdateError.message || 'Failed to update itinerary metadata');
                }

                // Calculate grand total for storage based on the current editor state
                const calculateGrandTotalForStorage = async (costingOptions: CostingOption[] | undefined, lead: Lead | undefined, meta: Partial<ItineraryMetadata>, itineraryData?: Partial<Itinerary>): Promise<number> => {
                    const costingOption = costingOptions?.[0];
                    if (!costingOption) return 0;

                    const adults = lead?.requirements?.adults || meta.adults || 0;
                    const children = lead?.requirements?.children || meta.children || 0;
                    const infants = lead?.requirements?.babies || meta.infants || 0;

                    if (costingOption.isManualCosting) {
                        // Manual costing
                        const subtotal = costingOption.manualPackageCost || 0;
                        let gst = 0;
                        let tcs = 0;
                        const flightFee = (costingOption.manualFlightPerAdult || 0) * adults +
                                         (costingOption.manualFlightPerChild || 0) * children +
                                         (costingOption.manualFlightPerInfant || 0) * infants;

                        if (costingOption.isGstApplied) {
                            const gstPercent = costingOption.gstPercentage || 5;
                            gst = subtotal * (gstPercent / 100);
                        }
                        if (costingOption.isTcsApplied) {
                            const tcsPercent = costingOption.tcsPercentage || 5;
                            tcs = (subtotal + gst) * (tcsPercent / 100);
                        }

                        return subtotal + gst + tcs + flightFee;
                    } else {
                        // Itemized costing - calculate full grand total
                        // Fetch FX rates if not available
                        let fxRates: Record<Currency, number> | null = null;
                        try {
                            const { data: ratesData } = await supabase
                                .from('fx_rates')
                                .select('currency, rate_to_inr')
                                .eq('is_active', true);
                            
                            if (ratesData) {
                                fxRates = {} as Record<Currency, number>;
                                ratesData.forEach(r => {
                                    fxRates![r.currency as Currency] = r.rate_to_inr || 1;
                                });
                                // Always include INR
                                fxRates['INR'] = 1;
                            }
                        } catch (error) {
                            console.error('Failed to fetch FX rates for grand total calculation:', error);
                        }

                        if (!fxRates) {
                            // If FX rates unavailable, return 0 (will be calculated on display)
                            return 0;
                        }

                        // Calculate base package and flights separately
                        // Flights should NOT have markup/discount applied - they're separate
                        let basePackageSubtotal = 0;
                        let flightFee = 0;
                        const categoryEnabled = costingOption.categoryEnabled || {};

                        // Process all costing categories
                        Object.entries(costingOption.costing || {}).forEach(([category, items]) => {
                            if (!Array.isArray(items) || items.length === 0) return;
                            if (!categoryEnabled[category as keyof typeof categoryEnabled]) return;
                            
                            const isFlight = category.startsWith('flights');
                            
                            items.forEach(item => {
                                if (!item.included || item.unitPrice === 0) return;
                                
                                const nights = (isFlight || category === 'sightseeing' || category === 'transfers' || category === 'visa' || category === 'insurance') 
                                    ? 1 
                                    : ((item as HotelCostingItem).nights || 1);
                                
                                const fxRate = fxRates![item.currency] || (item.currency === 'INR' ? 1 : 1);
                                
                                let effectiveQuantity = item.quantity || 1;
                                if (isFlight || category === 'transfers' || category === 'visa' || category === 'insurance') {
                                    const pricingType = item.pricingType || 'Per Adult';
                                    if (pricingType === 'Per Adult') effectiveQuantity = adults;
                                    else if (pricingType === 'Per Child') effectiveQuantity = children;
                                    else if (pricingType === 'Per Infant') effectiveQuantity = infants;
                                }
                                
                                if (isFlight) {
                                    // Flights: unitPrice × effectiveQuantity × fxRate (no markup, no discount)
                                    const flightCost = item.unitPrice * effectiveQuantity * fxRate;
                                    flightFee += flightCost;
                                } else {
                                    // Base package items: ((unitPrice × qty × FX_rate × nights) + 2) × 1.15
                                    const baseAmount = item.unitPrice * effectiveQuantity * fxRate * nights;
                                    const itemCost = (baseAmount + 2) * 1.15;
                                    basePackageSubtotal += itemCost;
                                }
                            });
                        });

                        // Apply markup ONLY to base package (not flights)
                        const markup = costingOption.markup || 0;
                        if (markup > 0) {
                            basePackageSubtotal = basePackageSubtotal * (1 + markup / 100);
                        }

                        // Apply discount ONLY to base package (not flights)
                        const discount = costingOption.discount || 0;
                        let discountAmount = 0;
                        if (discount > 0) {
                            discountAmount = basePackageSubtotal * (discount / 100);
                            basePackageSubtotal -= discountAmount;
                        }

                        // Calculate GST/TCS on base package (excluding flights)
                        let gst = 0;
                        let tcs = 0;

                        if (costingOption.isGstApplied) {
                            const gstPercent = costingOption.gstPercentage || 5;
                            gst = basePackageSubtotal * (gstPercent / 100);
                        }
                        if (costingOption.isTcsApplied) {
                            const tcsPercent = costingOption.tcsPercentage || 5;
                            tcs = (basePackageSubtotal + gst) * (tcsPercent / 100);
                        }

                        // Grand Total = Base Package + GST + TCS + Flight Fee
                        return basePackageSubtotal + gst + tcs + flightFee;
                    }
                };

                const lead = contextualData.lead || (metaRecord.lead_id ? await supabase.from('leads').select('*').eq('id', metaRecord.lead_id).single().then(r => r.data) : null);
                const grandTotal = await calculateGrandTotalForStorage(itineraryToSave.costing_options, lead, metaUpdates, itineraryToSave);

                // This ensures we always get the correct next version number, even if metaRecord.itinerary_versions is outdated
                const { data: latestVersionData, error: versionFetchError } = await supabase
                    .from('itinerary_versions')
                    .select('version_number')
                    .eq('itinerary_id', savedMetaId)
                    .order('version_number', { ascending: false })
                    .limit(1)
                    .single();

                if (versionFetchError && versionFetchError.code !== 'PGRST116') { // PGRST116 = no rows returned
                    console.error('[Itineraries] Error fetching latest version:', versionFetchError);
                    // Fallback to using versions array if DB query fails
                }

                const latestVersionNumber = latestVersionData?.version_number ?? (versions.length > 0 ? versions[0].version_number : 0);
                const nextVersionNumber = latestVersionNumber + 1;

                const { id, itinerary_id, version_number, ...restOfItinerary } = itineraryToSave as Itinerary;
                const newVersionData = {
                    ...restOfItinerary, itinerary_id: savedMetaId, version_number: nextVersionNumber,
                    modified_at: new Date().toISOString(), modified_by_staff_id: currentUser.id, cover_image_url: finalCoverUrl, gallery_image_urls: finalGalleryUrls,
                    grand_total: grandTotal > 0 ? grandTotal : null,
                };
                const { error: versionError } = await supabase.from('itinerary_versions').insert(newVersionData);
                if (versionError) {
                    if (versionError.code === '23505') {
                        addToast('Error: A version conflict occurred. Please try saving again.', 'error');
                        return null;
                    }
                    throw versionError;
                }
                addToast('Itinerary updated with a new version!', 'success');
            }

            // COMMON REFRESH LOGIC — refetch so list and detail stay in sync
            await refreshData();
            const { data: updatedMeta, error: fetchError } = await supabase.from('itineraries').select('*, itinerary_versions(*)').eq('id', savedMetaId).single();
            if (fetchError) {
                console.error('Failed to refetch itinerary after save:', fetchError);
                addToast('Saved but failed to refresh view. Please reopen the itinerary.', 'error');
                return null;
            }
            if (updatedMeta) {
                setSelectedItineraryMetadata(updatedMeta);
                setIsCreating(false);
                
                // Navigate to URL after save (lead-based or destination-based)
                const lead = contextualData.lead || (updatedMeta.lead_id ? leads.find(l => l.id === updatedMeta.lead_id) : null);
                navigate(generateItineraryUrl(updatedMeta, lead));
                
                return updatedMeta;
            }
            return null;

        } catch (error: any) {
            addToast(`Error saving itinerary: ${error.message}`, 'error');
            return null;
        }
    };

    const handleStatusUpdate = async (itineraryId: number, status: ItineraryStatus) => {
        try {
            const { error } = await supabase
                .from('itineraries')
                .update({ status: status })
                .eq('id', itineraryId);
            if (error) throw error;
            addToast(`Itinerary status updated to ${status}.`, 'success');
            await refreshData();

            if (selectedItineraryMetadata?.id === itineraryId) {
                const { data: updatedMeta, error: fetchError } = await supabase
                    .from('itineraries')
                    .select('*, itinerary_versions(*)')
                    .eq('id', itineraryId)
                    .single();
                if (!fetchError && updatedMeta) {
                    setSelectedItineraryMetadata(updatedMeta);
                }
            }
        } catch (error: any) {
            addToast(`Error updating status: ${error.message}`, 'error');
        }
    };


    if (view === 'detail') {
        return (
            <ItineraryDetailView
                itineraryMetadata={selectedItineraryMetadata}
                lead={contextualData.lead}
                customer={contextualData.customer}
                destination={contextualData.destination}
                initialTemplateMeta={templateInitialMeta}
                onClose={handleCloseDetailView}
                onSave={handleSaveItinerary}
                currentUser={currentUser}
                onStatusUpdate={handleStatusUpdate}
                refreshData={refreshData}
                invoices={invoices}
                isCreating={isCreating}
            />
        );
    }

    return (
        <ItineraryListView
            onSelectItinerary={handleSelectItinerary}
            onNewItinerary={(lead) => {
                const customer = lead.customer_id ? customers.find(c => c.id === lead.customer_id) : null;
                const destination = destinations.find(d => d.name === lead.destination) || null;
                setContextualData({ lead, customer: customer || null, destination });
                setTemplateInitialMeta(null);
                setIsCreating(true);
                setView('detail');
            }}
            onSelectTemplate={(payload) => {
                const destination = destinations.find(d => d.name === payload.destinationName) || null;
                setContextualData({ lead: null, customer: null, destination });
                setTemplateInitialMeta({ duration: payload.duration, creative_title: payload.creative_title });
                setIsCreating(true);
                setView('detail');
            }}
            onCloneComplete={(meta) => {
                setSelectedItineraryMetadata(meta);
                const lead = meta.lead_id ? leads.find(l => l.id === meta.lead_id) ?? null : null;
                const customer = meta.customer_id ? customers.find(c => c.id === meta.customer_id) ?? null : null;
                setContextualData({ lead, customer, destination: destinations.find(d => d.name === meta.destination) || null });
                setView('detail');
            }}
            onStatusUpdate={handleStatusUpdate}
            currentUser={currentUser}
        />
    );
};

const ItineraryListView: React.FC<{
    onSelectItinerary: (meta: ItineraryMetadata) => void;
    onNewItinerary: (lead: Lead) => void;
    onSelectTemplate: (payload: { destinationName: string; duration: string; creative_title: string }) => void;
    onStatusUpdate: (itineraryId: number, status: ItineraryStatus) => void;
    onCloneComplete?: (meta: ItineraryMetadata) => void;
    currentUser: LoggedInUser;
}> = ({ onSelectItinerary, onNewItinerary, onSelectTemplate, onStatusUpdate, onCloneComplete, currentUser }) => {
    const { itineraries, leads, customers, staff, destinations, branches, refreshData } = useData();
    const { navigate } = useRouter();
    const [searchTerm, setSearchTerm] = useState('');
    const [isNewModalOpen, setIsNewModalOpen] = useState(false);
    const [itineraryToClone, setItineraryToClone] = useState<ItineraryMetadata | null>(null);
    const [itineraryToArchive, setItineraryToArchive] = useState<ItineraryMetadata | null>(null);
    const [itineraryToRestore, setItineraryToRestore] = useState<ItineraryMetadata | null>(null);
    const [itineraryToDelete, setItineraryToDelete] = useState<ItineraryMetadata | null>(null);
    const [activeTab, setActiveTab] = useState<'Active' | 'Archived'>('Active');
    const isSuperAdmin = currentUser.role === 'Super Admin';
    const { addToast } = useToast();
    const [isFilterOpen, setIsFilterOpen] = useState(false);
    const filterRef = useRef<HTMLDivElement>(null);
    const [filters, setFilters] = useState({
        staffIds: [] as number[],
        statuses: [] as ItineraryStatus[],
        destinations: [] as string[]
    });

    // New State for View Mode and Pagination
    const [viewMode, setViewMode] = useState<'list' | 'grid'>('grid');
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(25);

    const customerMap = useMemo(() => new Map(customers.map(c => [c.id, c])), [customers]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (filterRef.current && !filterRef.current.contains(event.target as Node)) {
                setIsFilterOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleFilterChange = (filterType: 'staffIds' | 'statuses' | 'destinations', value: number | ItineraryStatus | string) => {
        setFilters(prev => {
            const currentValues = prev[filterType] as (number | ItineraryStatus | string)[];
            const newValues = currentValues.includes(value as any)
                ? currentValues.filter(v => v !== value)
                : [...currentValues, value];
            return { ...prev, [filterType]: newValues };
        });
    };

    const filteredItineraries = useMemo(() => {
        const activeStatuses: (ItineraryStatus | undefined)[] = [ItineraryStatus.Prepared, ItineraryStatus.Sent, ItineraryStatus.Confirmed, undefined];
        return itineraries
            .filter(meta => {
                const status = meta.status || ItineraryStatus.Prepared;
                if (activeTab === 'Active') {
                    return activeStatuses.includes(status);
                }
                return status === ItineraryStatus.Archived;
            })
            .filter(meta => {
                const customer = customerMap.get(meta.customer_id);
                const searchPool = `${meta.creative_title || ''} ${customer?.first_name || ''} ${customer?.last_name || ''} ${meta.destination || ''}`.toLowerCase();
                const searchMatch = searchPool.includes(searchTerm.toLowerCase());

                // Filter by destination
                const destinationMatch = filters.destinations.length === 0 ||
                    filters.destinations.some(d => meta.destination?.toLowerCase() === d.toLowerCase());

                // Filter by staff (created_by_staff_id)
                const staffMatch = filters.staffIds.length === 0 || filters.staffIds.includes(meta.created_by_staff_id);

                // Filter by status
                const statusMatch = filters.statuses.length === 0 || filters.statuses.includes(meta.status || ItineraryStatus.Prepared);

                return searchMatch && destinationMatch && staffMatch && statusMatch;
            })
            .sort((a, b) => new Date(b.modified_at).getTime() - new Date(a.modified_at).getTime());
    }, [itineraries, searchTerm, customerMap, activeTab, filters]);

    const paginatedItineraries = useMemo(() => {
        const startIndex = (currentPage - 1) * itemsPerPage;
        return filteredItineraries.slice(startIndex, startIndex + itemsPerPage);
    }, [filteredItineraries, currentPage, itemsPerPage]);

    useEffect(() => {
        setCurrentPage(1);
    }, [searchTerm, activeTab, itemsPerPage, filters]);


    const handleArchive = async () => {
        if (!itineraryToArchive) return;
        await onStatusUpdate(itineraryToArchive.id, ItineraryStatus.Archived);
        setItineraryToArchive(null);
    };

    const handleRestore = async () => {
        if (!itineraryToRestore) return;
        await onStatusUpdate(itineraryToRestore.id, ItineraryStatus.Prepared);
        setItineraryToRestore(null);
    };

    const handlePermanentDelete = async () => {
        if (!itineraryToDelete) return;
        try {
            const { error } = await supabase
                .from('itineraries')
                .delete()
                .eq('id', itineraryToDelete.id);

            if (error) throw error;

            addToast('Itinerary permanently deleted.', 'success');
            setItineraryToDelete(null);
            await refreshData();
        } catch (error: any) {
            addToast(`Error deleting itinerary: ${error.message}`, 'error');
        }
    };

    const handleLeadClick = (e: React.MouseEvent, leadId: number) => {
        e.stopPropagation();
        sessionStorage.setItem('viewLeadId', leadId.toString());
        navigate('/leads');
    };

    return (
        <div className="bg-white p-3 sm:p-4 rounded-lg shadow-sm">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 sm:gap-0 mb-4">
                <h1 className="text-lg sm:text-xl font-bold text-slate-800">Itineraries ({filteredItineraries.length})</h1>
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-2 w-full sm:w-auto">
                    {/* Search and Filter on same line for mobile */}
                    <div className="flex items-center gap-2 w-full sm:w-auto">
                        <div className="relative flex-1 sm:flex-none sm:w-auto">
                            <IconSearch className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 sm:w-5 sm:h-5 text-slate-400" />
                            <input type="text" placeholder="Search title, customer..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="pl-9 sm:pl-10 pr-4 py-2 w-full sm:w-64 text-sm bg-white border border-slate-300 rounded-md" />
                        </div>
                        {/* Filter Button */}
                        <div className="relative flex-shrink-0">
                            <button onClick={() => setIsFilterOpen(!isFilterOpen)} className="p-2 text-sm font-medium text-slate-600 bg-white border border-slate-300 rounded-md hover:bg-slate-50">
                                <IconFilter className="w-4 h-4 sm:w-5 sm:h-5" />
                            </button>
                            {isFilterOpen && (
                                <div ref={filterRef} className="absolute right-0 mt-2 w-[calc(100vw-2rem)] sm:w-80 max-w-sm bg-white rounded-md shadow-lg border z-10 p-4">
                                <h3 className="text-sm font-semibold mb-3 text-black">Filter Options</h3>
                                <div className="space-y-4 max-h-96 overflow-y-auto">
                                    <div>
                                        <label className="block text-xs font-medium text-slate-600 mb-2">By Status</label>
                                        <div className="grid grid-cols-2 gap-2">
                                            {Object.values(ItineraryStatus).filter(s => s !== ItineraryStatus.Archived).map(status => (
                                                <label key={status} className="flex items-center text-sm">
                                                    <input type="checkbox" checked={filters.statuses.includes(status)} onChange={() => handleFilterChange('statuses', status)} className="h-4 w-4 rounded border-slate-300 text-blue-600 bg-white" />
                                                    <span className="ml-2 text-slate-700">{status}</span>
                                                </label>
                                            ))}
                                        </div>
                                    </div>
                                    <hr />
                                    <div>
                                        <label className="block text-xs font-medium text-slate-600 mb-2">By Destination</label>
                                        <div className="space-y-1 max-h-48 overflow-y-auto">
                                            {destinations.map(dest => (
                                                <label key={dest.id} className="flex items-center text-sm">
                                                    <input type="checkbox" checked={filters.destinations.includes(dest.name.toLowerCase())} onChange={() => handleFilterChange('destinations', dest.name.toLowerCase())} className="h-4 w-4 rounded border-slate-300 text-blue-600 bg-white" />
                                                    <span className="ml-2 text-slate-700">{dest.name}</span>
                                                </label>
                                            ))}
                                        </div>
                                    </div>
                                    <hr />
                                    <div>
                                        <label className="block text-xs font-medium text-slate-600 mb-2">By Prepared By (Staff)</label>
                                        <div className="space-y-1 max-h-48 overflow-y-auto">
                                            {staff
                                                .filter(s => {
                                                    // Only show regular staff (role_id === 3), exclude managers (2), super admins (1), and AI/bots
                                                    if (s.role_id === 1 || s.role_id === 2) return false;

                                                    // Exclude AI/bot accounts
                                                    const nameLower = (s.name || '').toLowerCase();
                                                    const emailLower = (s.email || '').toLowerCase();
                                                    const isSystemByName = nameLower.includes('ai assistant') || nameLower.includes('assistant') || nameLower.includes('bot');
                                                    const isSystemByEmail = emailLower.includes('bot@') || emailLower.includes('no-reply') || emailLower.includes('noreply');
                                                    if (isSystemByName || isSystemByEmail) return false;

                                                    return true;
                                                })
                                                .map(s => (
                                                    <label key={s.id} className="flex items-center text-sm">
                                                        <input type="checkbox" checked={filters.staffIds.includes(s.id)} onChange={() => handleFilterChange('staffIds', s.id)} className="h-4 w-4 rounded border-slate-300 text-blue-600 bg-white" />
                                                        <img src={s.avatar_url} className="w-6 h-6 rounded-full ml-2 mr-1.5" />
                                                        <span className="text-slate-700">{s.name}</span>
                                                    </label>
                                                ))}
                                        </div>
                                    </div>
                                </div>
                                {(filters.staffIds.length > 0 || filters.statuses.length > 0 || filters.destinations.length > 0) && (
                                    <div className="mt-4 pt-4 border-t">
                                        <button onClick={() => setFilters({ staffIds: [], statuses: [], destinations: [] })} className="w-full px-4 py-2 text-sm font-medium text-red-600 bg-red-50 rounded-md hover:bg-red-100">
                                            Clear All Filters
                                        </button>
                                    </div>
                                )}
                            </div>
                        )}
                        </div>
                    </div>
                    {/* View Toggle - Hidden on mobile, visible on desktop */}
                    <div className="hidden sm:flex items-center bg-slate-100 p-0.5 rounded-lg border">
                        <button onClick={() => setViewMode('list')} className={`p-1.5 rounded-md ${viewMode === 'list' ? 'bg-white shadow-sm' : 'text-slate-500'}`}><IconListView className="w-5 h-5" /></button>
                        <button onClick={() => setViewMode('grid')} className={`p-1.5 rounded-md ${viewMode === 'grid' ? 'bg-white shadow-sm' : 'text-slate-500'}`}><IconGridView className="w-5 h-5" /></button>
                    </div>
                    {/* Desktop: Regular button, Mobile: Hidden (will show as FAB) */}
                    <button 
                        onClick={() => setIsNewModalOpen(true)} 
                        className="hidden sm:flex items-center gap-1.5 px-4 py-2 text-sm font-medium text-white bg-[#191974] rounded-[5px] hover:bg-[#13135c] transition-colors"
                    >
                        <IconPlus className="w-4 h-4" /> New Itinerary
                    </button>
                </div>
            </div>
            
            {/* Floating Action Button (FAB) - Mobile Only */}
            <button
                onClick={() => setIsNewModalOpen(true)}
                className="fixed bottom-6 right-6 sm:hidden z-50 w-14 h-14 bg-[#191974] hover:bg-[#13135c] text-white rounded-full shadow-lg hover:shadow-xl flex items-center justify-center transition-all duration-200 active:scale-95"
                aria-label="New Itinerary"
            >
                <IconPlus className="w-6 h-6" />
            </button>

            <div className="border-b border-slate-200">
                <nav className="-mb-px flex space-x-6" aria-label="Tabs">
                    <button onClick={() => setActiveTab('Active')} className={`whitespace-nowrap py-3 px-1 border-b-2 font-medium text-sm ${activeTab === 'Active' ? 'border-blue-600 text-blue-700' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}>Active</button>
                    <button onClick={() => setActiveTab('Archived')} className={`whitespace-nowrap py-3 px-1 border-b-2 font-medium text-sm ${activeTab === 'Archived' ? 'border-blue-600 text-blue-700' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'}`}>Archived</button>
                </nav>
            </div>

            {paginatedItineraries.length > 0 ? (
                viewMode === 'list' ? (
                    <div className="overflow-x-auto -mx-3 sm:mx-0 pb-20 sm:pb-0">
                        <table className="w-full text-xs sm:text-sm text-left text-slate-500 min-w-[640px]">
                            <thead className="text-xs text-slate-700 uppercase bg-slate-50">
                                <tr>
                                    <th className="px-6 py-3">Title</th>
                                    <th className="px-6 py-3">Lead</th>
                                    <th className="px-6 py-3">Customer</th>
                                    <th className="px-6 py-3">Status</th>
                                    <th className="px-6 py-3 text-center">Version</th>
                                    <th className="px-6 py-3">Prepared By</th>
                                    <th className="px-6 py-3">Last Modified</th>
                                    <th className="px-6 py-3">Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {paginatedItineraries.map(meta => {
                                    const customer = customerMap.get(meta.customer_id);
                                    const lead = leads.find(l => l.id === meta.lead_id);
                                    const staffCreator = staff.find(s => s.id === meta.created_by_staff_id);
                                    const latestVersion = meta.itinerary_versions?.length > 0
                                        ? Math.max(...meta.itinerary_versions.map(v => v.version_number))
                                        : 0;

                                    return (
                                        <tr key={meta.id} onClick={() => onSelectItinerary(meta)} className="bg-white border-b hover:bg-slate-50 cursor-pointer">
                                            <td className="px-6 py-4">
                                                <div className="font-semibold text-slate-800">{meta.creative_title}</div>
                                                <div className="text-xs text-slate-500">{meta.duration}</div>
                                            </td>
                                            <td onClick={(e) => lead && handleLeadClick(e, lead.id)} className="px-6 py-4 hover:underline text-blue-600">
                                                {lead ? <p className="font-medium">{generateBookingId(lead)}</p> : 'N/A'}
                                            </td>
                                            <td className="px-6 py-4">{customer ? `${customer.first_name} ${customer.last_name}` : 'N/A'}</td>
                                            <td className="px-6 py-4">
                                                <ItineraryStatusBadge status={meta.status} />
                                            </td>
                                            <td className="px-6 py-4 text-center font-medium text-slate-700">
                                                {latestVersion > 0 ? `v${latestVersion}` : '-'}
                                            </td>
                                            <td className="px-6 py-4">
                                                {staffCreator ? (
                                                    <div className="relative group flex items-center justify-center">
                                                        <img
                                                            src={staffCreator.avatar_url}
                                                            alt={staffCreator.name}
                                                            className="h-8 w-8 rounded-full object-cover"
                                                        />
                                                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-max p-2 text-xs text-white bg-slate-800 rounded-md shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-10 pointer-events-none">
                                                            {staffCreator.name}
                                                            <div className="absolute left-1/2 -translate-x-1/2 top-full w-0 h-0 border-x-4 border-x-transparent border-t-4 border-t-slate-800"></div>
                                                        </div>
                                                    </div>
                                                ) : 'N/A'}
                                            </td>
                                            <td className="px-6 py-4">{new Date(meta.modified_at).toLocaleDateString()}</td>
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-2">
                                                    {activeTab === 'Active' && (
                                                        <button onClick={(e) => { e.stopPropagation(); setItineraryToClone(meta); }} title="Clone" className="p-1 text-slate-500 hover:text-blue-600 rounded-full hover:bg-blue-50">
                                                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                                                        </button>
                                                    )}
                                                    {activeTab === 'Active' ? (
                                                        <button onClick={(e) => { e.stopPropagation(); setItineraryToArchive(meta); }} title="Archive" className="p-1 text-slate-500 hover:text-red-600 rounded-full hover:bg-red-50"><IconTrash className="w-5 h-5" /></button>
                                                    ) : (
                                                        <>
                                                            <button onClick={(e) => { e.stopPropagation(); setItineraryToRestore(meta); }} title="Restore" className="p-1 text-slate-500 hover:text-green-600 rounded-full hover:bg-green-50"><IconRefresh className="w-5 h-5" /></button>
                                                            {isSuperAdmin && (
                                                                <button onClick={(e) => { e.stopPropagation(); setItineraryToDelete(meta); }} title="Permanently Delete" className="p-1 text-red-600 hover:text-red-700 rounded-full hover:bg-red-50"><IconTrash className="w-5 h-5" /></button>
                                                            )}
                                                        </>
                                                    )}
                                                </div>
                                            </td>
                                        </tr>
                                    )
                                })}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <ItineraryGrid
                        itineraries={paginatedItineraries}
                        customerMap={customerMap}
                        leads={leads}
                        staff={staff}
                        onSelect={onSelectItinerary}
                        activeTab={activeTab}
                        onArchive={setItineraryToArchive}
                        onRestore={setItineraryToRestore}
                        onClone={setItineraryToClone}
                        onDelete={isSuperAdmin ? setItineraryToDelete : undefined}
                        isSuperAdmin={isSuperAdmin}
                        onNavigateLead={handleLeadClick}
                    />
                )
            ) : (
                <p className="text-center py-10 text-slate-500 pb-20 sm:pb-10">No itineraries found.</p>
            )}

            <div className="pb-20 sm:pb-0">
                <Pagination
                    currentPage={currentPage}
                    totalItems={filteredItineraries.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={setItemsPerPage}
                />
            </div>

            {isNewModalOpen && <NewItineraryModal leads={leads} customers={customers} destinations={destinations} onClose={() => setIsNewModalOpen(false)} onSelect={onNewItinerary} onSelectTemplate={onSelectTemplate} />}
            {itineraryToClone && (
                <CloneItineraryModal
                    source={itineraryToClone}
                    leads={leads}
                    customers={customers}
                    currentUser={currentUser}
                    branches={branches}
                    onClose={() => setItineraryToClone(null)}
                    onCloned={(newMeta) => {
                        setItineraryToClone(null);
                        refreshData().then(() => { onCloneComplete?.(newMeta); });
                    }}
                    addToast={addToast}
                />
            )}
            {itineraryToArchive && (
                <ConfirmationModal
                    title="Confirm Archive"
                    message={`Are you sure you want to archive "${itineraryToArchive.creative_title}"?`}
                    onConfirm={handleArchive}
                    onCancel={() => setItineraryToArchive(null)}
                />
            )}
            {itineraryToRestore && (
                <ConfirmationModal
                    title="Confirm Restore"
                    message={`Are you sure you want to restore "${itineraryToRestore.creative_title}"? It will be moved to the Active list.`}
                    onConfirm={handleRestore}
                    onCancel={() => setItineraryToRestore(null)}
                />
            )}
            {itineraryToDelete && (
                <ConfirmationModal
                    title="Permanently Delete Itinerary"
                    message={`Are you sure you want to permanently delete "${itineraryToDelete.creative_title}"? This action cannot be undone and will remove the itinerary from the system completely.`}
                    onConfirm={handlePermanentDelete}
                    onCancel={() => setItineraryToDelete(null)}
                />
            )}
        </div>
    );
};

const ConfirmationModal: React.FC<{ title: string; message: string; onConfirm: () => void; onCancel: () => void; }> = ({ title, message, onConfirm, onCancel }) => (
    <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center">
        <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-sm">
            <h3 className="text-lg font-semibold">{title}</h3>
            <p className="text-sm text-slate-600 my-4">{message}</p>
            <div className="flex justify-end gap-2">
                <button onClick={onCancel} className="px-4 py-2 text-sm rounded-md border">Cancel</button>
                <button onClick={onConfirm} className="px-4 py-2 text-sm rounded-md bg-red-600 text-white">Confirm</button>
            </div>
        </div>
    </div>
);


// Destination Search Dropdown Component
const DestinationSearchDropdown: React.FC<{
    destinations: Destination[];
    onSelect: (destination: Destination | null) => void;
    value?: string;
    onClear?: () => void;
}> = ({ destinations, onSelect, value, onClear }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);
    const dropdownMenuRef = useRef<HTMLDivElement>(null);
    const [dropdownPosition, setDropdownPosition] = useState({ top: 0, left: 0, width: 0 });

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Node;
            if (
                dropdownRef.current &&
                !dropdownRef.current.contains(target) &&
                dropdownMenuRef.current &&
                !dropdownMenuRef.current.contains(target)
            ) {
                setIsOpen(false);
                setSearchTerm('');
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        if (isOpen && inputRef.current) {
            const rect = inputRef.current.getBoundingClientRect();
            setDropdownPosition({
                top: rect.bottom + window.scrollY + 8,
                left: rect.left + window.scrollX,
                width: rect.width
            });
        }
    }, [isOpen]);

    const filteredDestinations = useMemo(() => {
        if (!searchTerm) return destinations;
        const term = searchTerm.toLowerCase();
        return destinations.filter(d =>
            d.name.toLowerCase().includes(term) ||
            (d.slug && d.slug.toLowerCase().includes(term))
        );
    }, [destinations, searchTerm]);

    const selectedDestination = destinations.find(d => d.name === value);

    return (
        <>
            <div ref={dropdownRef} className="relative w-full">
                <div className="relative">
                    <input
                        ref={inputRef}
                        type="text"
                        value={value || ''}
                        readOnly
                        onClick={() => setIsOpen(!isOpen)}
                        className="w-full p-2 border border-slate-300 rounded-md bg-white focus:border-[#191975] focus:ring-1 focus:ring-[#191975] outline-none cursor-pointer"
                        placeholder="Choose destination..."
                    />
                    <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none">
                        <IconChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
                    </div>
                </div>
            </div>
            {isOpen && (
                <div
                    ref={dropdownMenuRef}
                    className="fixed z-[99999] bg-white border border-slate-300 rounded-md shadow-2xl max-h-60 overflow-hidden"
                    style={{
                        top: `${dropdownPosition.top}px`,
                        left: `${dropdownPosition.left}px`,
                        width: `${Math.max(dropdownPosition.width, 300)}px`
                    }}
                >
                    <div className="p-3 border-b bg-slate-50">
                        <div className="relative">
                            <IconSearch className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input
                                type="text"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                placeholder="Search destinations..."
                                className="w-full pl-9 pr-3 py-2.5 text-sm border border-slate-300 rounded-md bg-white focus:outline-none focus:ring-2 focus:ring-[#191975] focus:border-[#191975]"
                                autoFocus
                            />
                        </div>
                    </div>
                    <div className="overflow-y-auto max-h-48">
                        {filteredDestinations.length === 0 ? (
                            <div className="p-3 text-sm text-slate-500 text-center">No destinations found</div>
                        ) : (
                            filteredDestinations.map(destination => (
                                <div
                                    key={destination.id}
                                    onClick={() => {
                                        onSelect(destination);
                                        setIsOpen(false);
                                        setSearchTerm('');
                                    }}
                                    className="p-3 hover:bg-blue-50 cursor-pointer border-b border-slate-100 last:border-b-0 transition-colors"
                                >
                                    <div className="font-medium text-slate-900 text-sm">{destination.name}</div>
                                </div>
                            ))
                        )}
                    </div>
                    {selectedDestination && onClear && (
                        <div className="p-2 border-t bg-slate-50">
                            <button
                                onClick={() => {
                                    onClear();
                                    setIsOpen(false);
                                    setSearchTerm('');
                                }}
                                className="w-full text-sm text-red-600 hover:text-red-800 py-1.5 font-medium"
                            >
                                Clear Selection
                            </button>
                        </div>
                    )}
                </div>
            )}
        </>
    );
};

const LeadSearchDropdown: React.FC<{
    leads: Lead[];
    customers: Customer[];
    onSelect: (lead: Lead | null) => void;
    value?: number;
    onClear?: () => void;
}> = ({ leads, customers, onSelect, value, onClear }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);
    const dropdownMenuRef = useRef<HTMLDivElement>(null);
    const [dropdownPosition, setDropdownPosition] = useState({ top: 0, left: 0, width: 0 });

    const customerMap = useMemo(() => new Map(customers.map(c => [c.id, c])), [customers]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Node;
            if (
                dropdownRef.current &&
                !dropdownRef.current.contains(target) &&
                dropdownMenuRef.current &&
                !dropdownMenuRef.current.contains(target)
            ) {
                setIsOpen(false);
                setSearchTerm('');
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        if (isOpen && inputRef.current) {
            const rect = inputRef.current.getBoundingClientRect();
            setDropdownPosition({
                top: rect.bottom + window.scrollY + 8,
                left: rect.left + window.scrollX,
                width: rect.width
            });
        }
    }, [isOpen]);

    // Filter to only Tour Package leads
    const tourPackageLeads = useMemo(() => {
        return leads.filter(lead => lead.services && lead.services.includes(Service.Tour));
    }, [leads]);

    const filteredLeads = useMemo(() => {
        if (!searchTerm) return tourPackageLeads.slice(0, 50); // Limit to 50 for performance
        const term = searchTerm.toLowerCase();
        return tourPackageLeads.filter(lead => {
            const customer = customerMap.get(lead.customer_id);
            const customerName = customer ? `${customer.first_name} ${customer.last_name}`.toLowerCase() : '';
            const destination = lead.destination?.toLowerCase() || '';
            const leadId = lead.id.toString();
            return customerName.includes(term) ||
                destination.includes(term) ||
                leadId.includes(term) ||
                (customer?.email && customer.email.toLowerCase().includes(term)) ||
                (customer?.phone && customer.phone.includes(term));
        }).slice(0, 50);
    }, [tourPackageLeads, searchTerm, customerMap]);

    const selectedLead = tourPackageLeads.find(l => l.id === value);

    const getLeadDisplayText = (lead: Lead) => {
        const customer = customerMap.get(lead.customer_id);
        const customerName = customer ? `${customer.first_name} ${customer.last_name}` : 'Unknown Customer';
        return `#${lead.id} - ${customerName} - ${lead.destination || 'N/A'}`;
    };

    return (
        <>
            <div ref={dropdownRef} className="relative w-full">
                <div className="relative">
                    <input
                        ref={inputRef}
                        type="text"
                        value={selectedLead ? getLeadDisplayText(selectedLead) : ''}
                        readOnly
                        onClick={() => setIsOpen(!isOpen)}
                        className="w-full p-2 border border-slate-300 rounded-md bg-white focus:border-[#191975] focus:ring-1 focus:ring-[#191975] outline-none cursor-pointer"
                        placeholder="Search for a lead..."
                    />
                    <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none">
                        <IconChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
                    </div>
                </div>
            </div>
            {isOpen && (
                <div
                    ref={dropdownMenuRef}
                    className="fixed z-[99999] bg-white border border-slate-300 rounded-md shadow-2xl max-h-60 overflow-hidden"
                    style={{
                        top: `${dropdownPosition.top}px`,
                        left: `${dropdownPosition.left}px`,
                        width: `${Math.max(dropdownPosition.width, 400)}px`
                    }}
                >
                    <div className="p-3 border-b bg-slate-50">
                        <div className="relative">
                            <IconSearch className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input
                                type="text"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                placeholder="Search by customer name, destination, lead ID..."
                                className="w-full pl-9 pr-3 py-2.5 text-sm border border-slate-300 rounded-md bg-white focus:outline-none focus:ring-2 focus:ring-[#191975] focus:border-[#191975]"
                                autoFocus
                            />
                        </div>
                    </div>
                    <div className="overflow-y-auto max-h-48">
                        {filteredLeads.length === 0 ? (
                            <div className="p-3 text-sm text-slate-500 text-center">
                                {tourPackageLeads.length === 0
                                    ? 'No Tour Package leads available'
                                    : 'No leads found matching your search'}
                            </div>
                        ) : (
                            filteredLeads.map(lead => {
                                const customer = customerMap.get(lead.customer_id);
                                return (
                                    <div
                                        key={lead.id}
                                        onClick={() => {
                                            onSelect(lead);
                                            setIsOpen(false);
                                            setSearchTerm('');
                                        }}
                                        className="p-3 hover:bg-blue-50 cursor-pointer border-b border-slate-100 last:border-b-0 transition-colors"
                                    >
                                        <div className="font-medium text-slate-900 text-sm">
                                            #{lead.id} - {customer ? `${customer.first_name} ${customer.last_name}` : 'Unknown Customer'}
                                        </div>
                                        <div className="text-xs text-slate-500 mt-0.5">
                                            {lead.destination || 'N/A'} • {lead.duration || 'N/A'}
                                        </div>
                                    </div>
                                );
                            })
                        )}
                    </div>
                    {selectedLead && onClear && (
                        <div className="p-2 border-t bg-slate-50">
                            <button
                                onClick={() => {
                                    onClear();
                                    setIsOpen(false);
                                    setSearchTerm('');
                                }}
                                className="w-full text-sm text-red-600 hover:text-red-800 py-1.5 font-medium"
                            >
                                Clear Selection
                            </button>
                        </div>
                    )}
                </div>
            )}
        </>
    );
};

const CloneItineraryModal: React.FC<{
    source: ItineraryMetadata;
    leads: Lead[];
    customers: Customer[];
    currentUser: LoggedInUser;
    branches: Branch[];
    onClose: () => void;
    onCloned: (newMeta: ItineraryMetadata) => void;
    addToast: (msg: string, type: 'success' | 'error' | 'info') => void;
}> = ({ source, leads, customers, currentUser, branches, onClose, onCloned, addToast }) => {
    const [cloneAsTemplate, setCloneAsTemplate] = useState(true);
    const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
    const [durationDays, setDurationDays] = useState<number | ''>(() => {
        const d = source.duration;
        if (!d) return '';
        const m = /^(\d+)/.exec(String(d));
        return m ? parseInt(m[1], 10) : '';
    });
    const [submitting, setSubmitting] = useState(false);

    const durationString = durationDays !== '' && Number.isInteger(Number(durationDays)) && Number(durationDays) > 0
        ? `${durationDays} Day${Number(durationDays) !== 1 ? 's' : ''}`
        : (source.duration || '');

    const handleClone = async () => {
        if (!cloneAsTemplate && !selectedCustomer) {
            addToast('Select a customer or clone as template.', 'error');
            return;
        }
        setSubmitting(true);
        try {
            let leadId: number | null = null;
            const customerId = selectedCustomer?.id ?? null;
            const finalDuration = durationString || source.duration;
            const finalBranchId = currentUser.branch_id;

            if (!cloneAsTemplate && selectedCustomer) {
                const branchIds = currentUser.branch_id === 1 ? [1] : [currentUser.branch_id, 1];
                const activity: Activity = { id: Date.now(), type: 'Lead Created', description: 'Lead created from cloned itinerary.', user: currentUser.name, timestamp: new Date().toISOString() };
                const dbData = {
                    customer_id: selectedCustomer.id,
                    destination: source.destination || '',
                    travel_date: null as string | null,
                    duration: finalDuration,
                    status: LeadStatus.Enquiry,
                    lead_type: LeadType.Cold,
                    priority: Priority.Low,
                    requirements: {
                        adults: source.adults ?? 2,
                        children: source.children ?? 0,
                        babies: source.infants ?? 0,
                        hotelPreference: HotelPreference.NoPreference,
                        stayPreference: StayPreference.NoPreference,
                        rooms: [{ id: 1, adults: source.adults ?? 2, children: source.children ?? 0 }],
                    },
                    summary: '',
                    notes: [],
                    activity: [activity],
                    branch_ids: branchIds,
                    last_updated: new Date().toISOString(),
                };
                const { data: newLeadData, error: leadErr } = await supabase.from('leads').insert(dbData).select().single();
                if (leadErr) throw leadErr;
                leadId = newLeadData.id;
            }

            const { data: newMetaRow, error: metaErr } = await supabase.from('itineraries').insert({
                lead_id: leadId,
                customer_id: customerId,
                creative_title: source.creative_title + (leadId ? ' (Copy)' : ' (Template)'),
                duration: finalDuration,
                destination: source.destination,
                travel_date: source.travel_date || null,
                starting_point: source.starting_point || '',
                adults: source.adults ?? 2,
                children: source.children ?? 0,
                infants: source.infants ?? 0,
                created_by_staff_id: currentUser.id,
                branch_id: finalBranchId,
                is_final: false,
                modified_at: new Date().toISOString(),
                status: ItineraryStatus.Prepared,
                show_payment_button: false,
                emergency_contacts: (source as any).emergency_contacts || [],
            }).select().single();
            if (metaErr) throw metaErr;
            const newId = newMetaRow.id;

            const { data: latestVersion, error: verErr } = await supabase
                .from('itinerary_versions')
                .select('*')
                .eq('itinerary_id', source.id)
                .order('version_number', { ascending: false })
                .limit(1)
                .single();
            if (verErr || !latestVersion) {
                addToast('Could not copy itinerary content. New itinerary created with no version.', 'error');
                await supabase.from('itineraries').select('*, itinerary_versions(*)').eq('id', newId).single().then(r => { if (r.data) onCloned(r.data); });
                onClose();
                return;
            }

            const { id: _vid, itinerary_id: _iid, version_number: _vn, ...rest } = latestVersion as any;
            const { error: insertVerErr } = await supabase.from('itinerary_versions').insert({
                ...rest,
                itinerary_id: newId,
                version_number: 1,
                modified_at: new Date().toISOString(),
                modified_by_staff_id: currentUser.id,
            });
            if (insertVerErr) throw insertVerErr;

            if (leadId) {
                const { data: leadRow } = await supabase.from('leads').select('itinerary_ids').eq('id', leadId).single();
                const ids = (leadRow?.itinerary_ids as number[] | null) || [];
                if (!ids.includes(newId)) {
                    await supabase.from('leads').update({ itinerary_ids: [...ids, newId] }).eq('id', leadId);
                }
            }

            const { data: newMeta, error: fetchErr } = await supabase.from('itineraries').select('*, itinerary_versions(*)').eq('id', newId).single();
            if (fetchErr || !newMeta) {
                addToast('Cloned but failed to open. Refresh the list.', 'info');
                onClose();
                return;
            }
            addToast('Itinerary cloned successfully.', 'success');
            onCloned(newMeta as ItineraryMetadata);
            onClose();
        } catch (e: any) {
            addToast(e?.message || 'Failed to clone itinerary.', 'error');
        } finally {
            setSubmitting(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-40 flex items-center justify-center" onClick={onClose}>
            <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-md" onClick={e => e.stopPropagation()}>
                <h3 className="text-lg font-semibold text-slate-800 mb-4">Clone itinerary</h3>
                <p className="text-sm text-slate-600 mb-4">"{source.creative_title}" — {source.destination}</p>
                <div className="space-y-4 mb-4">
                    <label className="flex items-center gap-2">
                        <input type="radio" checked={cloneAsTemplate} onChange={() => { setCloneAsTemplate(true); setSelectedCustomer(null); }} />
                        <span>Clone as template (by destination)</span>
                    </label>
                    <label className="flex items-center gap-2">
                        <input type="radio" checked={!cloneAsTemplate} onChange={() => setCloneAsTemplate(false)} />
                        <span>Clone for a customer</span>
                    </label>
                    {!cloneAsTemplate && (
                        <div className="ml-6">
                            <CustomerSearchDropdown customers={customers} selectedCustomer={selectedCustomer} onSelect={setSelectedCustomer} />
                        </div>
                    )}
                    <div>
                        <label className="block text-xs font-medium text-slate-600 mb-1">Duration (days, optional)</label>
                        <input type="number" min={1} value={durationDays === '' ? '' : durationDays} onChange={e => { const v = e.target.value; setDurationDays(v === '' ? '' : parseInt(v, 10)); }} placeholder="e.g. 5" className="w-full p-2 border border-slate-300 rounded-md text-sm" />
                    </div>
                </div>
                <div className="flex justify-end gap-2">
                    <button onClick={onClose} className="px-4 py-2 text-sm rounded-md border">Cancel</button>
                    <button onClick={handleClone} disabled={submitting || (!cloneAsTemplate && !selectedCustomer)} className="px-4 py-2 text-sm rounded-md bg-[#191974] text-white disabled:bg-slate-400">{submitting ? 'Cloning…' : 'Clone'}</button>
                </div>
            </div>
        </div>
    );
};

const NewItineraryModal: React.FC<{
    leads: Lead[];
    customers: Customer[];
    destinations: Destination[];
    onClose: () => void;
    onSelect: (lead: Lead) => void;
    onSelectTemplate: (payload: { destinationName: string; duration: string; creative_title: string }) => void;
}> = ({ leads, customers, destinations, onClose, onSelect, onSelectTemplate }) => {
    const [mode, setMode] = useState<'lead' | 'template'>('lead');
    const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
    const [templateDest, setTemplateDest] = useState('');
    const [templateDuration, setTemplateDuration] = useState('5D/4N');
    const [templateTitle, setTemplateTitle] = useState('');

    const handleSubmitLead = () => {
        if (selectedLead) {
            onSelect(selectedLead);
            onClose();
        }
    };

    const handleSubmitTemplate = () => {
        if (templateDest.trim()) {
            onSelectTemplate({
                destinationName: templateDest.trim(),
                duration: templateDuration.trim() || '5D/4N',
                creative_title: templateTitle.trim() || `${templateDest.trim()} Package`
            });
            onClose();
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-40 flex items-center justify-center" onClick={onClose}>
            <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-md" onClick={e => e.stopPropagation()}>
                <h3 className="text-lg font-semibold text-slate-800 mb-4">Create New Itinerary</h3>
                <div className="flex border-b border-slate-200 mb-4">
                    <button type="button" onClick={() => setMode('lead')} className={`px-4 py-2 text-sm font-medium border-b-2 ${mode === 'lead' ? 'border-[#191974] text-[#191974]' : 'border-transparent text-slate-500'}`}>For a lead</button>
                    <button type="button" onClick={() => setMode('template')} className={`px-4 py-2 text-sm font-medium border-b-2 ${mode === 'template' ? 'border-[#191974] text-[#191974]' : 'border-transparent text-slate-500'}`}>Template (by destination)</button>
                </div>
                {mode === 'lead' ? (
                    <>
                        <p className="text-sm text-slate-600 mb-4">Select a lead to create a new itinerary for.</p>
                        <div className="mb-4">
                            <LeadSearchDropdown leads={leads} customers={customers} value={selectedLead?.id} onSelect={setSelectedLead} onClear={() => setSelectedLead(null)} />
                        </div>
                        <div className="flex justify-end gap-2">
                            <button onClick={onClose} className="px-4 py-2 text-sm rounded-md border">Cancel</button>
                            <button onClick={handleSubmitLead} disabled={!selectedLead} className="px-4 py-2 text-sm rounded-md bg-[#191974] text-white disabled:bg-slate-400">Create</button>
                        </div>
                    </>
                ) : (
                    <>
                        <p className="text-sm text-slate-600 mb-4">Create a destination-based template. You can clone it later for any lead or customer.</p>
                        <div className="space-y-4 mb-4">
                            <div>
                                <label className="block text-xs font-medium text-slate-600 mb-1">Destination *</label>
                                <select value={templateDest} onChange={e => setTemplateDest(e.target.value)} className="w-full p-2 border border-slate-300 rounded-md text-sm">
                                    <option value="">Select destination</option>
                                    {destinations.map(d => <option key={d.id} value={d.name}>{d.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-slate-600 mb-1">Duration</label>
                                <input type="text" value={templateDuration} onChange={e => setTemplateDuration(e.target.value)} placeholder="e.g. 5D/4N" className="w-full p-2 border border-slate-300 rounded-md text-sm" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-slate-600 mb-1">Title</label>
                                <input type="text" value={templateTitle} onChange={e => setTemplateTitle(e.target.value)} placeholder="e.g. Rajasthan 5D/4N Package" className="w-full p-2 border border-slate-300 rounded-md text-sm" />
                            </div>
                        </div>
                        <div className="flex justify-end gap-2">
                            <button onClick={onClose} className="px-4 py-2 text-sm rounded-md border">Cancel</button>
                            <button onClick={handleSubmitTemplate} disabled={!templateDest.trim()} className="px-4 py-2 text-sm rounded-md bg-[#191974] text-white disabled:bg-slate-400">Create template</button>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
};

const ImageUploader: React.FC<{
    src?: string | null;
    onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    isEditing: boolean;
    className?: string;
    label: string;
}> = ({ src, onChange, isEditing, className = '', label }) => {
    const inputRef = useRef<HTMLInputElement>(null);
    const handleImageClick = () => {
        if (isEditing) {
            inputRef.current?.click();
        }
    };

    const placeholder = 'https://placehold.co/600x400/e2e8f0/64748b?text=Image';

    return (
        <div
            className={`relative rounded-lg bg-slate-200 overflow-hidden group ${isEditing ? 'cursor-pointer' : ''} ${className || 'h-full'}`}
            onClick={handleImageClick}
            title={isEditing ? `Click to change ${label}` : label}
        >
            <img src={src || placeholder} alt={label} className="w-full h-full object-cover transition-transform group-hover:scale-105" />
            {isEditing && (
                <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <div className="text-center text-white">
                        <IconPencil className="w-8 h-8 mx-auto" />
                        <span className="mt-1 text-sm font-semibold">Change</span>
                    </div>
                </div>
            )}
            <input type="file" ref={inputRef} onChange={onChange} className="hidden" accept="image/png, image/jpeg" />
        </div>
    );
};


const VersionSelector: React.FC<{
    versions: Itinerary[];
    activeVersion: Itinerary | null;
    onSelect: (version: Itinerary) => void;
}> = ({ versions, activeVersion, onSelect }) => {
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    if (versions.length <= 1) return null;

    return (
        <div className="relative" ref={dropdownRef}>
            <button onClick={() => setIsOpen(!isOpen)} className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-slate-700 bg-slate-100 rounded-[5px] hover:bg-slate-200">
                Version {activeVersion?.version_number}
                <IconChevronDown className="w-4 h-4" />
            </button>
            {isOpen && (
                <div className="absolute top-full right-0 mt-2 w-48 bg-white rounded-md shadow-lg border z-20">
                    <ul className="p-1">
                        {versions.map((v) => {
                            const isLatest = versions.length > 0 && v.version_number === versions[0].version_number;
                            return (
                            <li key={v.id}>
                                <button
                                    onClick={() => { onSelect(v); setIsOpen(false); }}
                                    className={`w-full text-left p-2 text-sm rounded-md ${v.id === activeVersion?.id ? 'bg-blue-50 text-blue-700' : 'hover:bg-slate-100'}`}
                                >
                                        Version {v.version_number} {isLatest && '(Latest)'}
                                </button>
                            </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </div>
    );
};

// Customer Search Dropdown Component
const CustomerSearchDropdown: React.FC<{
    customers: Customer[];
    selectedCustomer: Customer | null;
    onSelect: (customer: Customer | null) => void;
}> = ({ customers, selectedCustomer, onSelect }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);
    const dropdownMenuRef = useRef<HTMLDivElement>(null);
    const [dropdownPosition, setDropdownPosition] = useState({ top: 0, left: 0, width: 0 });

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Node;
            if (
                dropdownRef.current &&
                !dropdownRef.current.contains(target) &&
                dropdownMenuRef.current &&
                !dropdownMenuRef.current.contains(target)
            ) {
                setIsOpen(false);
                setSearchTerm('');
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        if (isOpen) {
            const handleScroll = (event: Event) => {
                const target = event.target as Node;
                // Check if scroll is happening inside the dropdown menu or its children
                if (dropdownMenuRef.current && dropdownMenuRef.current.contains(target)) {
                    // Allow scrolling inside dropdown - don't close
                    return;
                }
                // Also check if the active element is inside the dropdown (for keyboard scrolling)
                const activeElement = document.activeElement;
                if (dropdownMenuRef.current && activeElement && dropdownMenuRef.current.contains(activeElement)) {
                    return;
                }
                // Close dropdown if scrolling outside (page scroll)
                setIsOpen(false);
                setSearchTerm('');
            };
            // Listen to scroll on window and document to catch page scrolling
            window.addEventListener('scroll', handleScroll, true);
            document.addEventListener('scroll', handleScroll, true);
            return () => {
                window.removeEventListener('scroll', handleScroll, true);
                document.removeEventListener('scroll', handleScroll, true);
            };
        }
    }, [isOpen]);

    useEffect(() => {
        if (isOpen && inputRef.current) {
            const rect = inputRef.current.getBoundingClientRect();
            setDropdownPosition({
                top: rect.bottom + window.scrollY + 8,
                left: rect.left + window.scrollX,
                width: rect.width
            });
        }
    }, [isOpen]);

    const filteredCustomers = useMemo(() => {
        if (!searchTerm) return customers.slice(0, 50); // Limit to 50 for performance
        const term = searchTerm.toLowerCase();
        return customers.filter(c =>
            `${c.first_name} ${c.last_name}`.toLowerCase().includes(term) ||
            c.phone?.toLowerCase().includes(term) ||
            c.email?.toLowerCase().includes(term)
        ).slice(0, 50);
    }, [customers, searchTerm]);

    return (
        <>
            <div ref={dropdownRef} className="relative w-full">
                <div className="relative">
                    <input
                        ref={inputRef}
                        type="text"
                        value={selectedCustomer ? `${selectedCustomer.salutation} ${selectedCustomer.first_name} ${selectedCustomer.last_name}` : ''}
                        readOnly
                        onClick={() => setIsOpen(!isOpen)}
                        className="w-full p-1.5 border border-slate-300 rounded-md bg-white focus:border-[#191975] focus:ring-1 focus:ring-[#191975] outline-none cursor-pointer text-sm font-bold text-slate-800"
                        placeholder="Select customer..."
                    />
                    <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none">
                        <IconChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
                    </div>
                </div>
            </div>
            {isOpen && (
                <div
                    ref={dropdownMenuRef}
                    className="fixed z-[99999] bg-white border border-slate-300 rounded-md shadow-2xl max-h-60 overflow-hidden"
                    style={{
                        top: `${dropdownPosition.top}px`,
                        left: `${dropdownPosition.left}px`,
                        width: `${Math.max(dropdownPosition.width, 300)}px`
                    }}
                >
                    <div className="p-3 border-b bg-slate-50">
                        <div className="relative">
                            <IconSearch className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input
                                type="text"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                placeholder="Search customers..."
                                className="w-full pl-9 pr-3 py-2.5 text-sm border border-slate-300 rounded-md bg-white focus:outline-none focus:ring-2 focus:ring-[#191975] focus:border-[#191975]"
                                autoFocus
                            />
                        </div>
                    </div>
                    <div className="overflow-y-auto max-h-48">
                        {filteredCustomers.length === 0 ? (
                            <div className="p-3 text-sm text-slate-500 text-center">No customers found</div>
                        ) : (
                            <>
                                {selectedCustomer && (
                                    <div
                                        onClick={() => {
                                            onSelect(null);
                                            setIsOpen(false);
                                            setSearchTerm('');
                                        }}
                                        className="p-3 hover:bg-red-50 cursor-pointer border-b border-slate-100 transition-colors"
                                    >
                                        <div className="text-sm text-red-600 font-medium">Clear Selection</div>
                                    </div>
                                )}
                                {filteredCustomers.map(customer => (
                                    <div
                                        key={customer.id}
                                        onClick={() => {
                                            onSelect(customer);
                                            setIsOpen(false);
                                            setSearchTerm('');
                                        }}
                                        className={`p-3 hover:bg-blue-50 cursor-pointer border-b border-slate-100 last:border-b-0 transition-colors ${selectedCustomer?.id === customer.id ? 'bg-blue-50' : ''}`}
                                    >
                                        <div className="font-medium text-slate-900 text-sm">{customer.salutation} {customer.first_name} {customer.last_name}</div>
                                        <div className="text-xs text-slate-500 mt-1">
                                            {customer.phone && `📞 ${customer.phone}`}
                                            {customer.email && ` • ✉️ ${customer.email}`}
                                        </div>
                                    </div>
                                ))}
                            </>
                        )}
                    </div>
                </div>
            )}
        </>
    );
};

// Multi-Destination Dropdown Component
const MultiDestinationDropdown: React.FC<{
    destinations: Destination[];
    selectedDestinations: string[];
    onSelect: (destinations: string[]) => void;
}> = ({ destinations, selectedDestinations, onSelect }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);
    const dropdownMenuRef = useRef<HTMLDivElement>(null);
    const [dropdownPosition, setDropdownPosition] = useState({ top: 0, left: 0, width: 0 });

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Node;
            if (
                dropdownRef.current &&
                !dropdownRef.current.contains(target) &&
                dropdownMenuRef.current &&
                !dropdownMenuRef.current.contains(target)
            ) {
                setIsOpen(false);
                setSearchTerm('');
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        if (isOpen) {
            const handleScroll = (event: Event) => {
                const target = event.target as Node;
                // Check if scroll is happening inside the dropdown menu or its children
                if (dropdownMenuRef.current && dropdownMenuRef.current.contains(target)) {
                    // Allow scrolling inside dropdown - don't close
                    return;
                }
                // Also check if the active element is inside the dropdown (for keyboard scrolling)
                const activeElement = document.activeElement;
                if (dropdownMenuRef.current && activeElement && dropdownMenuRef.current.contains(activeElement)) {
                    return;
                }
                // Close dropdown if scrolling outside (page scroll)
                setIsOpen(false);
                setSearchTerm('');
            };
            // Listen to scroll on window and document to catch page scrolling
            window.addEventListener('scroll', handleScroll, true);
            document.addEventListener('scroll', handleScroll, true);
            return () => {
                window.removeEventListener('scroll', handleScroll, true);
                document.removeEventListener('scroll', handleScroll, true);
            };
        }
    }, [isOpen]);

    useEffect(() => {
        if (isOpen && inputRef.current) {
            const rect = inputRef.current.getBoundingClientRect();
            const dropdownWidth = Math.max(rect.width, 300);
            const viewportWidth = window.innerWidth;
            const scrollX = window.scrollX;
            const padding = 8; // Padding from viewport edges

            // Calculate left position, ensuring dropdown stays within viewport
            let left = rect.left + scrollX;

            // If dropdown would go off right edge, adjust to stay within viewport
            if (left + dropdownWidth > viewportWidth + scrollX - padding) {
                left = Math.max(padding, viewportWidth + scrollX - dropdownWidth - padding);
            }
            // If dropdown would go off left edge, align to left edge with padding
            if (left < scrollX + padding) {
                left = scrollX + padding;
            }

            setDropdownPosition({
                top: rect.bottom + window.scrollY + 8,
                left: left,
                width: dropdownWidth
            });
        }
    }, [isOpen]);

    const filteredDestinations = useMemo(() => {
        if (!searchTerm) return destinations;
        const term = searchTerm.toLowerCase();
        return destinations.filter(d =>
            d.name.toLowerCase().includes(term) ||
            (d.slug && d.slug.toLowerCase().includes(term))
        );
    }, [destinations, searchTerm]);

    const toggleDestination = (destName: string) => {
        if (selectedDestinations.includes(destName)) {
            onSelect(selectedDestinations.filter(d => d !== destName));
        } else {
            onSelect([...selectedDestinations, destName]);
        }
    };

    return (
        <>
            <div ref={dropdownRef} className="relative w-full">
                <div className="relative">
                    <input
                        ref={inputRef}
                        type="text"
                        value={selectedDestinations.length > 0 ? selectedDestinations.join(', ') : ''}
                        readOnly
                        onClick={() => setIsOpen(!isOpen)}
                        className="w-full p-1.5 border border-slate-300 rounded-md bg-white focus:border-[#191975] focus:ring-1 focus:ring-[#191975] outline-none cursor-pointer text-sm font-bold text-slate-800"
                        placeholder="Select destinations..."
                    />
                    <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none">
                        <IconChevronDown className={`w-4 h-4 text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
                    </div>
                </div>
            </div>
            {isOpen && (
                <div
                    ref={dropdownMenuRef}
                    className="fixed z-[99999] bg-white border border-slate-300 rounded-md shadow-2xl max-h-60 overflow-hidden"
                    style={{
                        top: `${dropdownPosition.top}px`,
                        left: `${dropdownPosition.left}px`,
                        width: `${Math.max(dropdownPosition.width, 300)}px`
                    }}
                >
                    <div className="p-3 border-b bg-slate-50">
                        <div className="relative">
                            <IconSearch className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input
                                type="text"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                placeholder="Search destinations..."
                                className="w-full pl-9 pr-3 py-2.5 text-sm border border-slate-300 rounded-md bg-white focus:outline-none focus:ring-2 focus:ring-[#191975] focus:border-[#191975]"
                                autoFocus
                            />
                        </div>
                    </div>
                    <div className="overflow-y-auto max-h-48">
                        {filteredDestinations.length === 0 ? (
                            <div className="p-3 text-sm text-slate-500 text-center">No destinations found</div>
                        ) : (
                            filteredDestinations.map(destination => {
                                const isSelected = selectedDestinations.includes(destination.name);
                                return (
                                    <div
                                        key={destination.id}
                                        onClick={() => toggleDestination(destination.name)}
                                        className={`p-3 hover:bg-blue-50 cursor-pointer border-b border-slate-100 last:border-b-0 transition-colors flex items-center justify-between ${isSelected ? 'bg-blue-50' : ''}`}
                                    >
                                        <div className="font-medium text-slate-900 text-sm">{destination.name}</div>
                                        {isSelected && <span className="text-blue-600">✓</span>}
                                    </div>
                                );
                            })
                        )}
                    </div>
                </div>
            )}
        </>
    );
};

